import React from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

class ErrorBoundary extends React.Component {
    constructor(props) {
        super(props);
        this.state = { hasError: false, error: null, errorInfo: null };
    }

    static getDerivedStateFromError(error) {
        // Update state so the next render will show the fallback UI.
        return { hasError: true };
    }

    componentDidCatch(error, errorInfo) {
        // You can also log the error to an error reporting service
        console.error("Uncaught error:", error, errorInfo);
        this.setState({ error, errorInfo });
    }

    render() {
        if (this.state.hasError) {
            // You can render any custom fallback UI
            return (
                <div style={{
                    height: '100vh',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    backgroundColor: '#f8fafc',
                    color: '#1e293b',
                    textAlign: 'center',
                    fontFamily: "'Montserrat', sans-serif"
                }}>
                    <div style={{
                        background: '#fff',
                        padding: '2rem 3rem',
                        borderRadius: '16px',
                        boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1), 0 8px 10px -6px rgba(0, 0, 0, 0.1)',
                        maxWidth: '500px',
                        width: '90%'
                    }}>
                        <div style={{
                            background: '#fee2e2',
                            padding: '1rem',
                            borderRadius: '50%',
                            display: 'inline-flex',
                            marginBottom: '1.5rem'
                        }}>
                            <AlertTriangle size={48} color="#ef4444" />
                        </div>

                        <h1 style={{ fontSize: '1.5rem', fontWeight: '700', marginBottom: '0.5rem', color: '#0f172a' }}>
                            Ops! Algo deu errado.
                        </h1>

                        <p style={{ color: '#64748b', marginBottom: '2rem', lineHeight: '1.5' }}>
                            Ocorreu um erro inesperado e o sistema precisou parar.
                            <br />
                            Não se preocupe, seus dados estão seguros.
                        </p>

                        <button
                            onClick={() => window.location.reload()}
                            style={{
                                display: 'inline-flex',
                                alignItems: 'center',
                                gap: '0.5rem',
                                padding: '0.75rem 1.5rem',
                                background: '#0f172a',
                                color: '#fff',
                                border: 'none',
                                borderRadius: '8px',
                                fontWeight: '600',
                                fontSize: '0.95rem',
                                cursor: 'pointer',
                                transition: 'opacity 0.2s',
                            }}
                            onMouseOver={(e) => e.target.style.opacity = '0.9'}
                            onMouseOut={(e) => e.target.style.opacity = '1'}
                        >
                            <RefreshCw size={18} /> Recarregar Página
                        </button>

                        {/* Optional: details for debugging (hidden by default or small) */}
                        {this.state.error && process.env.NODE_ENV === 'development' && (
                            <details style={{ marginTop: '2rem', textAlign: 'left', color: '#94a3b8', fontSize: '0.75rem', overflow: 'auto', maxHeight: '100px' }}>
                                <summary>Detalhes do Erro</summary>
                                <pre>{this.state.error.toString()}</pre>
                                <pre>{this.state.errorInfo.componentStack}</pre>
                            </details>
                        )}
                    </div>
                </div>
            );
        }

        return this.props.children;
    }
}

export default ErrorBoundary;

import React, { useState, useEffect } from 'react'
import { supabase } from '../services/supabaseClient'
import {
    X,
    Briefcase,
    MapPin,
    ExternalLink,
    Copy,
    Check,
    Sparkles,
    MessageCircle,
    ArrowRight,
    ArrowLeft,
    Info,
    Brain,
    Send
} from 'lucide-react'

const LeadDetailModal = ({ lead, campaignLead, onClose }) => {
    const [interactions, setInteractions] = useState([])
    const [loadingInteractions, setLoadingInteractions] = useState(false)
    const [copiedIdx, setCopiedIdx] = useState(null)
    const [enrichedData, setEnrichedData] = useState(null) // Local state for fresh DB data
    const [draftMessage, setDraftMessage] = useState('') // Human-in-the-loop message editing
    const [selectedSuggestionIdx, setSelectedSuggestionIdx] = useState(null)

    useEffect(() => {
        if (lead?.id) fetchInteractions()
    }, [lead?.id])

    const fetchInteractions = async () => {
        setLoadingInteractions(true)
        try {
            // 1. Fetch Interactions
            const { data: interactionsData, error: interactionsError } = await supabase
                .from('interactions')
                .select('*')
                .eq('lead_id', lead.id)
                .order('interaction_date', { ascending: false })
                .limit(5)

            if (interactionsError) throw interactionsError
            setInteractions(interactionsData || [])

            // 2. FETCH MISSING DATA (Trust Score, Sentiment, AI Replies, Summary)
            // Since the main view can't join, we fetch fresh data here
            const { data: leadData, error: leadError } = await supabase
                .from('leads')
                .select('cadence_stage, sentiment, sentiment_reasoning, ai_suggested_replies, conversation_summary, icp_reason')
                .eq('id', lead.id)
                .single()

            if (leadData) {
                console.log('[LeadDetailModal] Fetched fresh enriched data:', leadData)
                // Merge fresh data into the local lead object mechanism
                // We'll update a local state or ref, but since 'lead' is a prop, 
                // we might need a local state for the enriched fields.
                setEnrichedData(leadData)
            }

        } catch (err) {
            console.error('Error fetching details:', err)
        } finally {
            setLoadingInteractions(false)
        }
    }

    const copyToClipboard = (text, idx) => {
        navigator.clipboard.writeText(text)
        setCopiedIdx(idx)
        setTimeout(() => setCopiedIdx(null), 2000)
    }

    // ============ DATA TRIAD LOGIC ============

    // 1. QUALITY (A/B/C tier)
    const getQualityData = () => {
        const tier = lead?.icp_score?.toUpperCase() || 'C'
        const configs = {
            'A': { label: 'A', percent: 100, color: '#10b981', bg: 'bg-emerald-500', text: 'text-emerald-400' },
            'B': { label: 'B', percent: 66, color: '#f59e0b', bg: 'bg-amber-500', text: 'text-amber-400' },
            'C': { label: 'C', percent: 33, color: '#ef4444', bg: 'bg-red-500', text: 'text-red-400' }
        }
        return configs[tier] || configs['C']
    }

    // 2. INTERACTION (message volume)
    const getInteractionData = () => {
        const count = lead?.total_interactions || 0
        if (count >= 10) return { percent: 100, color: '#10b981', label: count, text: 'text-emerald-400' }
        if (count >= 5) return { percent: 66, color: '#f59e0b', label: count, text: 'text-amber-400' }
        return { percent: Math.max(10, count * 10), color: '#ef4444', label: count, text: 'text-red-400' }
    }

    // 3. CADENCE STAGE → Trust/Proximity Level
    // In outbound prospecting, cadence stages reflect growing trust:
    // G1 (first contact) → G7+ (high trust / ready to close)
    const getCadenceData = () => {
        const stage = enrichedData?.cadence_stage
            ?? lead?.cadence_stage
            ?? lead?.leads?.cadence_stage
            ?? ''

        // Extract numeric level from stage (e.g. "G5" → 5, "G1" → 1)
        const match = stage?.toString().match(/(\d+)/)
        const level = match ? parseInt(match[1], 10) : 0

        // Map level to trust progression (outbound context)
        const trustLevels = [
            { max: 0, label: 'No Cadence', desc: 'This lead has not started the prospecting cadence yet.', percent: 5, color: '#94a3b8', text: 'text-slate-400' },
            { max: 1, label: 'First Contact', desc: 'Lead received the first touch. Initial trust level.', percent: 15, color: '#3b82f6', text: 'text-blue-400' },
            { max: 2, label: 'Recognition', desc: 'Lead starts to recognize you. Trust is building.', percent: 30, color: '#06b6d4', text: 'text-cyan-400' },
            { max: 3, label: 'Consideration', desc: 'Lead shows openness to talk. Growing trust.', percent: 45, color: '#f59e0b', text: 'text-amber-400' },
            { max: 4, label: 'Active Interest', desc: 'Engaged and interested lead. Good trust established.', percent: 60, color: '#f97316', text: 'text-orange-400' },
            { max: 5, label: 'Relationship', desc: 'Lead trusts you as a reference. Solid relationship.', percent: 75, color: '#10b981', text: 'text-emerald-400' },
            { max: 6, label: 'High Trust', desc: 'Highly engaged lead. Ready for a proposal.', percent: 90, color: '#22c55e', text: 'text-green-400' },
            { max: Infinity, label: 'Ready to Close', desc: 'Maximum trust reached. Ideal time for conversion.', percent: 100, color: '#eab308', text: 'text-yellow-400' }
        ]

        const config = trustLevels.find(t => level <= t.max) || trustLevels[0]

        return { ...config, stage, level }
    }

    const quality = getQualityData()
    const interaction = getInteractionData()
    const cadence = getCadenceData()
    // Prioritize fresh AI replies
    const aiReplies = enrichedData?.ai_suggested_replies || lead?.ai_suggested_replies || []

    if (!lead) return null

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md p-4" onClick={onClose}>
            <div
                className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl max-h-[92vh] overflow-hidden border border-slate-200"
                onClick={e => e.stopPropagation()}
            >
                {/* ========== HEADER: Identity (Keep Dark) ========== */}
                <div className="relative px-6 pt-6 pb-4 bg-gradient-to-b from-slate-900 to-slate-800 rounded-t-3xl">
                    <button
                        onClick={onClose}
                        className="absolute top-4 right-4 p-2 rounded-full hover:bg-white/10 transition text-slate-400 hover:text-white"
                    >
                        <X size={20} />
                    </button>

                    <div className="flex items-center gap-4">
                        {/* Avatar */}
                        <div className="w-16 h-16 shrink-0">
                            <LeadAvatar
                                lead={lead}
                                className="w-full h-full shadow-lg"
                            />
                        </div>

                        {/* Name + Headline */}
                        <div className="flex-1 min-w-0">
                            <h2 className="text-xl font-bold text-white truncate">{lead.nome || 'Lead'}</h2>
                            <p className="text-slate-400 text-sm flex items-center gap-1.5 mt-0.5 truncate">
                                <Briefcase size={14} className="shrink-0" />
                                {lead.headline || 'No role provided'}
                            </p>
                            {lead.location && (
                                <p className="text-slate-500 text-xs flex items-center gap-1 mt-1">
                                    <MapPin size={12} /> {lead.location}
                                </p>
                            )}
                        </div>

                        {lead.linkedin_url && (
                            <a
                                href={lead.linkedin_url}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="shrink-0 p-2.5 rounded-xl bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white transition"
                            >
                                <ExternalLink size={18} />
                            </a>
                        )}
                    </div>
                </div>

                {/* ========== TRUST TRIAD: 3 Stat Badges ========== */}
                <div className="px-6 py-5 border-b border-slate-200 bg-slate-50">
                    <div className="grid grid-cols-3 gap-3">
                        {/* Badge 1: Qualificação ICP */}
                        <div className={`flex flex-col items-center gap-1 py-3 px-2 rounded-2xl border-2 ${quality.label === 'A' ? 'bg-emerald-50 border-emerald-300' :
                            quality.label === 'B' ? 'bg-amber-50 border-amber-300' :
                                'bg-red-50 border-red-300'
                            }`}>
                            <span className={`text-2xl font-black ${quality.text}`}>{quality.label}</span>
                            <span className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider text-center leading-tight">ICP Qualification</span>
                        </div>

                        {/* Badge 2: Interações */}
                        <div className={`flex flex-col items-center gap-1 py-3 px-2 rounded-2xl border-2 ${interaction.percent === 100 ? 'bg-emerald-50 border-emerald-300' :
                            interaction.percent === 66 ? 'bg-amber-50 border-amber-300' :
                                'bg-red-50 border-red-300'
                            }`}>
                            <span className={`text-2xl font-black ${interaction.text}`}>{interaction.label}</span>
                            <span className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider text-center leading-tight">Interactions</span>
                        </div>

                        {/* Badge 3: Cadência */}
                        <div className="flex flex-col items-center gap-1 py-3 px-2 rounded-2xl border-2 bg-blue-50 border-blue-200">
                            <span className={`text-2xl font-black ${cadence.text}`}>{cadence.stage || '—'}</span>
                            <span className="text-[10px] text-slate-500 font-semibold uppercase tracking-wider text-center leading-tight">Cadence</span>
                            {cadence.label && <span className={`text-[9px] font-medium ${cadence.text} leading-tight text-center`}>{cadence.label}</span>}
                        </div>
                    </div>

                    {/* ICP Reasoning */}
                    <div className="mt-4 p-3 bg-white rounded-xl border border-slate-200 shadow-sm">
                        <p className="text-xs text-slate-600">
                            <span className="font-bold text-slate-800 mr-1">Why ICP {quality.label}?</span>
                            {enrichedData?.icp_reason || lead?.icp_reason || "No reasoning available."}
                        </p>
                    </div>

                    {/* Cadence Stage Explanation */}
                    <div className="mt-3 p-3 bg-white rounded-xl border border-slate-200 shadow-sm">
                        <p className="text-xs text-slate-600">
                            <span className="font-bold text-slate-800 mr-1">Cadence Level ({cadence.stage || '—'}):</span>
                            {cadence.desc}
                        </p>
                    </div>
                </div>

                {/* ========== SCROLLABLE CONTENT (Light Theme) ========== */}
                <div className="px-6 pb-6 pt-4 overflow-y-auto max-h-[calc(92vh-340px)] space-y-5 bg-white">

                    {/* ========== AI BRIEFING (Context) ========== */}
                    {(enrichedData?.conversation_summary || lead?.conversation_summary) && (
                        <div className="bg-blue-50 rounded-xl p-4 border border-blue-200">
                            <div className="flex items-center gap-2 mb-2">
                                <Brain size={16} className="text-blue-600" />
                                <span className="text-xs font-bold text-blue-700 uppercase tracking-wider">Conversation Summary</span>
                            </div>
                            <p className="text-sm text-slate-700 leading-relaxed">
                                {enrichedData?.conversation_summary || lead?.conversation_summary}
                            </p>
                        </div>
                    )}

                    {/* ========== ACTION ENGINE: AI Suggestions (Enhanced) ========== */}
                    <div>
                        <div className="flex items-center gap-2 mb-3">
                            <Sparkles size={16} className="text-amber-500" />
                            <span className="text-xs font-bold text-slate-600 uppercase tracking-wider">Action Engine</span>
                        </div>

                        {aiReplies.length > 0 ? (
                            <div className="space-y-3">
                                {aiReplies.map((reply, idx) => {
                                    // Support both old string format and new object format
                                    const text = typeof reply === 'object' ? reply.text : reply
                                    const strategy = typeof reply === 'object' ? reply.strategy : null
                                    const isSelected = selectedSuggestionIdx === idx

                                    return (
                                        <div
                                            key={idx}
                                            className={`group relative p-4 rounded-2xl border transition-all cursor-pointer ${isSelected
                                                ? 'ring-2 ring-violet-500 border-violet-400 bg-violet-50'
                                                : idx === 0
                                                    ? 'bg-gradient-to-r from-violet-100 to-indigo-100 border-violet-300 hover:border-violet-400'
                                                    : 'bg-slate-50 border-slate-200 hover:border-slate-300'
                                                }`}
                                            onClick={() => {
                                                setDraftMessage(text)
                                                setSelectedSuggestionIdx(idx)
                                            }}
                                        >
                                            {idx === 0 && (
                                                <span className="absolute -top-2 left-3 px-2 py-0.5 bg-violet-600 text-white text-[10px] font-bold uppercase rounded-full">
                                                    Recommended
                                                </span>
                                            )}
                                            <p className="text-sm text-slate-700 leading-relaxed pr-10">
                                                "{text}"
                                            </p>
                                            {/* Strategy Explanation */}
                                            {strategy && (
                                                <p className="text-xs text-slate-500 italic mt-2 border-t border-slate-200 pt-2">
                                                    💡 <span className="font-medium">Strategy:</span> {strategy}
                                                </p>
                                            )}
                                            <button
                                                className="absolute top-4 right-4 p-2 rounded-lg bg-slate-100 hover:bg-slate-200 text-slate-500 hover:text-slate-700 transition opacity-0 group-hover:opacity-100"
                                                onClick={(e) => { e.stopPropagation(); copyToClipboard(text, idx) }}
                                            >
                                                {copiedIdx === idx ? <Check size={16} className="text-emerald-500" /> : <Copy size={16} />}
                                            </button>
                                        </div>
                                    )
                                })}

                                {/* ========== HUMAN-IN-THE-LOOP EDITOR ========== */}
                                {draftMessage && (
                                    <div className="mt-4 p-4 bg-white rounded-xl border-2 border-dashed border-blue-300 space-y-3">
                                        <div className="flex items-center gap-2 text-xs text-blue-600 font-bold uppercase tracking-wider">
                                            <MessageCircle size={14} />
                                            Edit Message Before Sending
                                        </div>
                                        <textarea
                                            className="w-full h-28 p-3 bg-slate-50 border border-slate-200 rounded-lg text-sm text-slate-700 focus:outline-none focus:border-blue-400 focus:ring-2 focus:ring-blue-100 resize-none"
                                            value={draftMessage}
                                            onChange={(e) => setDraftMessage(e.target.value)}
                                            placeholder="Edit the message here..."
                                        />
                                        <div className="flex gap-2">
                                            <button
                                                onClick={() => copyToClipboard(draftMessage, -1)}
                                                className="flex-1 py-2.5 rounded-lg bg-slate-100 text-slate-600 font-semibold text-sm hover:bg-slate-200 transition flex items-center justify-center gap-2"
                                            >
                                                <Copy size={14} />
                                                Copy
                                            </button>
                                            <button
                                                onClick={() => {
                                                    console.log('[LinkedIn Send] Simulating send:', draftMessage)
                                                    alert('✅ Message ready to send! (Simulation)')
                                                    setDraftMessage('')
                                                    setSelectedSuggestionIdx(null)
                                                }}
                                                className="flex-1 py-2.5 rounded-lg bg-blue-600 text-white font-semibold text-sm hover:bg-blue-700 transition flex items-center justify-center gap-2 shadow-lg shadow-blue-200"
                                            >
                                                <Send size={14} />
                                                Send via LinkedIn
                                            </button>
                                        </div>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="p-5 rounded-2xl bg-slate-50 border border-dashed border-slate-300 text-center">
                                <Sparkles size={24} className="mx-auto text-slate-400 mb-2" />
                                <p className="text-sm text-slate-500">
                                    No suggestions available yet.<br />
                                    <span className="text-slate-400">Sync messages to generate.</span>
                                </p>
                            </div>
                        )}
                    </div>

                    {/* ========== RECENT MESSAGES ========== */}
                    {interactions.length > 0 && (
                        <div>
                            <div className="flex items-center gap-2 mb-3">
                                <MessageCircle size={16} className="text-slate-500" />
                                <span className="text-xs font-bold text-slate-600 uppercase tracking-wider">Recent Messages</span>
                            </div>
                            <div className="space-y-2">
                                {interactions.slice(0, 3).map((msg, idx) => (
                                    <div key={idx} className="p-3 rounded-xl bg-slate-50 border border-slate-200">
                                        <div className="flex items-center justify-between mb-1.5">
                                            <div className="flex items-center gap-2">
                                                <span className={`w-5 h-5 rounded-full flex items-center justify-center ${msg.direction === 'outbound' ? 'bg-blue-100 text-blue-600' : 'bg-emerald-100 text-emerald-600'
                                                    }`}>
                                                    {msg.direction === 'outbound' ? <ArrowRight size={10} /> : <ArrowLeft size={10} />}
                                                </span>
                                                <span className={`text-xs font-semibold ${msg.direction === 'outbound' ? 'text-blue-600' : 'text-emerald-600'
                                                    }`}>
                                                    {msg.direction === 'outbound' ? 'Sent' : 'Received'}
                                                </span>
                                            </div>
                                            <span className="text-[10px] text-slate-400">
                                                {new Date(msg.interaction_date).toLocaleDateString('en-US')}
                                            </span>
                                        </div>
                                        <p className="text-sm text-slate-700 line-clamp-2">{msg.content || '—'}</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {!loadingInteractions && interactions.length === 0 && (
                        <div className="text-center py-6 text-slate-600 text-sm">
                            <MessageCircle size={24} className="mx-auto mb-2 opacity-50" />
                            No messages recorded
                        </div>
                    )}
                </div>
            </div>
        </div>
    )
}

export default LeadDetailModal

import React, { useState, useEffect, useMemo, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '../services/supabaseClient'
import { useClientSelection } from '../contexts/ClientSelectionContext'
import {
    Flame,
    Send,
    MessageSquare,
    FileText,
    ExternalLink,
    CheckCircle2,
    Trophy,
    PartyPopper,
    Loader2,
    RefreshCw,
    AlertTriangle,
    Rocket,
    Clock,
    Zap,
    Target,
    Hammer,
    Linkedin,
    Sparkles,
    TrendingUp,
    HandMetal,
    MessageCircle,
    Users,
    DollarSign,
    Snowflake
} from 'lucide-react'
import LeadAvatar from './LeadAvatar'
import UnifiedLeadModal from './UnifiedLeadModal'

// ═══════════════════════════════════════════════
// CONSTANTS
// ═══════════════════════════════════════════════

const HOT_STAGES = ['G4', 'G5']

const CADENCE_LABELS = {
    G1: 'Primeiro Contato',
    G2: 'Networking',
    G3: 'Nutrição',
    G4: 'Aquecido',
    G5: 'Pronto p/ Fechar',
}

const CADENCE_STYLES = {
    G1: 'bg-gray-100 text-gray-600 border-gray-300',
    G2: 'bg-blue-50 text-blue-600 border-blue-200',
    G3: 'bg-cyan-50 text-cyan-700 border-cyan-200',
    G4: 'bg-orange-50 text-orange-600 border-orange-200',
    G5: 'bg-red-50 text-red-600 border-red-200',
}

const COLUMN_THEMES = {
    hot: {
        borderTop: 'linear-gradient(90deg, #ef4444, #f97316)',
        headerBg: 'bg-red-500/[0.08]',
        headerBorder: 'border-red-500/15',
        countBg: 'bg-red-500/10',
        countText: 'text-red-400',
        countBorder: 'border-red-500/20',
        iconColor: 'text-red-400',
        cardBorder: 'border-l-orange-500/60',
        columnBg: 'rgba(239, 68, 68, 0.02)',
        emptyBg: 'bg-red-500/5',
        emptyBorder: 'border-red-500/10',
    },
    cold: {
        borderTop: 'linear-gradient(90deg, #3b82f6, #94a3b8)',
        headerBg: 'bg-blue-500/[0.08]',
        headerBorder: 'border-blue-500/15',
        countBg: 'bg-blue-500/10',
        countText: 'text-blue-400',
        countBorder: 'border-blue-500/20',
        iconColor: 'text-blue-400',
        cardBorder: 'border-l-blue-500/30',
        columnBg: 'rgba(59, 130, 246, 0.02)',
        emptyBg: 'bg-blue-500/5',
        emptyBorder: 'border-blue-500/10',
    },
    warm: {
        borderTop: 'linear-gradient(90deg, #eab308, #f59e0b)',
        headerBg: 'bg-yellow-500/[0.08]',
        headerBorder: 'border-yellow-500/15',
        countBg: 'bg-yellow-500/10',
        countText: 'text-yellow-400',
        countBorder: 'border-yellow-500/20',
        iconColor: 'text-yellow-400',
        cardBorder: 'border-l-yellow-500/50',
        columnBg: 'rgba(234, 179, 8, 0.02)',
        emptyBg: 'bg-yellow-500/5',
        emptyBorder: 'border-yellow-500/10',
    }
}

const VISIBLE_COLD_CARDS = 8

// ═══════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════

const SalesCockpit = () => {
    const { selectedClientId } = useClientSelection()
    const [tasks, setTasks] = useState([])
    const [doneCount, setDoneCount] = useState(0)
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState(null)
    const [refreshing, setRefreshing] = useState(false)
    const [completingIds, setCompletingIds] = useState(new Set())
    const [showAllCold, setShowAllCold] = useState(false)

    // Overdue Tasks State
    const [overdueTasks, setOverdueTasks] = useState([])
    const [showOverdue, setShowOverdue] = useState(false)

    const fetchTasks = useCallback(async (isRefresh = false) => {
        if (!selectedClientId) {
            setTasks([])
            setDoneCount(0)
            setLoading(false)
            return
        }

        if (isRefresh) setRefreshing(true)
        else setLoading(true)

        setError(null)

        try {
            const todayStart = new Date()
            todayStart.setHours(0, 0, 0, 0)

            const [pendingResult, doneResult, overdueResult] = await Promise.all([
                supabase
                    .from('tasks')
                    .select('*, lead:leads!inner(id, client_id, nome, empresa, headline, linkedin_profile_url, cadence_stage, total_interactions_count, avatar_url)')
                    .eq('client_id', selectedClientId)
                    .eq('leads.client_id', selectedClientId)
                    .neq('leads.is_blacklisted', true)
                    .eq('status', 'PENDING')
                    .gte('created_at', todayStart.toISOString())
                    .order('created_at', { ascending: true })
                    .limit(30),
                supabase
                    .from('tasks')
                    .select('id, leads!inner(client_id)', { count: 'exact' })
                    .eq('client_id', selectedClientId)
                    .eq('leads.client_id', selectedClientId)
                    .neq('leads.is_blacklisted', true)
                    .eq('status', 'COMPLETED')
                    .gte('completed_at', `${new Date().toISOString().split('T')[0]}T00:00:00`)
                    .limit(1),
                supabase
                    .from('tasks')
                    .select('*, lead:leads!inner(id, client_id, nome, empresa, headline, linkedin_profile_url, cadence_stage, total_interactions_count, avatar_url)')
                    .eq('client_id', selectedClientId)
                    .eq('leads.client_id', selectedClientId)
                    .neq('leads.is_blacklisted', true)
                    .eq('status', 'PENDING')
                    .lt('created_at', todayStart.toISOString())
                    .order('created_at', { ascending: false })
                    .limit(50)
            ])

            if (pendingResult.error) throw pendingResult.error
            if (overdueResult.error) {
                console.error('Overdue query error:', overdueResult.error)
                throw overdueResult.error
            }

            const activeTasks = pendingResult.data || []
            setTasks(activeTasks)
            setDoneCount(doneResult.count || 0)

            console.log('[DEBUG] Overdue tasks raw data:', overdueResult.data)
            setOverdueTasks(overdueResult.data || [])
        } catch (err) {
            console.error('Error fetching cockpit tasks:', err)
            setError('Failed to load tasks. Please try again.')
        } finally {
            setLoading(false)
            setRefreshing(false)
        }
    }, [selectedClientId])

    useEffect(() => {
        fetchTasks()
    }, [fetchTasks])

    const handleComplete = async (taskId) => {
        setCompletingIds(prev => new Set(prev).add(taskId))

        // Find task before removing it to get lead ID (check both lists)
        const taskToComplete = tasks.find(t => t.id === taskId) || overdueTasks.find(t => t.id === taskId)

        setTasks(prev => prev.filter(t => t.id !== taskId))
        setOverdueTasks(prev => prev.filter(t => t.id !== taskId))

        // Only increment done count if it was a today's task being completed, or keep it simple and increment regardless.
        // Usually, we just increment.
        setDoneCount(prev => prev + 1)

        try {
            const { error: updateError } = await supabase
                .from('tasks')
                .update({ status: 'COMPLETED', completed_at: new Date().toISOString() })
                .eq('id', taskId)

            if (updateError) throw updateError

            // Sync with leads table so realtime updates trigger correctly in Inbox
            if (taskToComplete?.lead?.id) {
                await supabase
                    .from('leads')
                    .update({ last_task_completed_at: new Date().toISOString() })
                    .eq('id', taskToComplete.lead.id)
            }

        } catch (err) {
            console.error('Error completing task:', err)
            fetchTasks(true)
        } finally {
            setCompletingIds(prev => {
                const next = new Set(prev)
                next.delete(taskId)
                return next
            })
        }
    }

    const navigate = useNavigate()
    const [selectedLeadForModal, setSelectedLeadForModal] = useState(null)

    const handleExecute = (leadId) => {
        if (leadId) {
            navigate(`/sales/inbox?leadId=${leadId}`)
        }
    }

    // Split by cadence_stage (HOT: G4/G5, WARM: G2/G3, COLD: G1)
    const { hotTasks, warmTasks, coldTasks } = useMemo(() => {
        const hot = tasks.filter(t =>
            t.lead?.cadence_stage === 'G4' || t.lead?.cadence_stage === 'G5'
        );

        const warm = tasks.filter(t =>
            t.lead?.cadence_stage === 'G2' || t.lead?.cadence_stage === 'G3'
        );

        const cold = tasks.filter(t =>
            t.lead?.cadence_stage === 'G1'
        );

        return { hotTasks: hot, warmTasks: warm, coldTasks: cold }
    }, [tasks])

    const totalMissions = tasks.length + doneCount
    const progressPercent = totalMissions > 0 ? Math.round((doneCount / totalMissions) * 100) : 0
    const allDone = tasks.length === 0 && !loading

    // Cold column: show first N or all
    const visibleColdTasks = showAllCold ? coldTasks : coldTasks.slice(0, VISIBLE_COLD_CARDS)
    const hiddenColdCount = coldTasks.length - VISIBLE_COLD_CARDS

    // --- LOADING STATE ---
    if (loading) {
        return (
            <div className="glass-panel rounded-2xl p-8 mb-8 animate-fade-in-up">
                <div className="flex flex-col items-center justify-center py-12 gap-4">
                    <Loader2 className="w-8 h-8 animate-spin text-primary" />
                    <span className="tracking-wide uppercase text-xs font-bold text-gray-400">
                        Loading tasks...
                    </span>
                </div>
            </div>
        )
    }

    // --- ERROR STATE ---
    if (error) {
        return (
            <div className="glass-panel rounded-2xl p-8 mb-8 border-red-500/20 animate-fade-in-up">
                <div className="flex flex-col items-center justify-center py-12 gap-4 text-center">
                    <div className="w-14 h-14 rounded-2xl bg-red-500/10 border border-red-500/20 flex items-center justify-center">
                        <AlertTriangle size={28} className="text-red-400" />
                    </div>
                    <p className="text-sm text-gray-400">{error}</p>
                    <button
                        onClick={() => fetchTasks()}
                        className="px-4 py-2 rounded-lg bg-white/5 hover:bg-white/10 text-gray-300 text-sm font-medium border border-glass-border transition-all"
                    >
                        Try again
                    </button>
                </div>
            </div>
        )
    }

    // --- NO CLIENT ---
    if (!selectedClientId) {
        return (
            <div className="glass-panel rounded-2xl p-8 mb-8 animate-fade-in-up">
                <div className="flex flex-col items-center justify-center py-8 gap-3 text-center">
                    <Target size={32} className="text-gray-600" />
                    <p className="text-sm text-gray-400">Select a client to view the Daily Tasks.</p>
                </div>
            </div>
        )
    }

    return (
        <div className="mb-8 animate-fade-in-up">
            {/* ═══════════════════════════════════════ */}
            {/* HEADER + PROGRESS                      */}
            {/* ═══════════════════════════════════════ */}
            <div className="bg-white rounded-2xl border border-gray-200 p-5 sm:p-6 mb-5 shadow-sm">
                <div className="flex items-start justify-between gap-4 mb-5">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-orange-50 border border-orange-200 flex items-center justify-center">
                            <Rocket size={20} className="text-orange-500" />
                        </div>
                        <div>
                            <h2 className="text-xl sm:text-2xl font-bold tracking-tight text-gray-900 mb-0.5">
                                Daily Tasks 🚀
                            </h2>
                            <p className="text-sm text-gray-500">
                                {hotTasks.length > 0
                                    ? <><span className="text-red-400 font-semibold">{hotTasks.length} hot</span> · {warmTasks.length} nurturing · {coldTasks.length} new contacts</>
                                    : tasks.length > 0
                                        ? <>{tasks.length} pending task(s)</>
                                        : 'No pending tasks!'
                                }
                            </p>
                        </div>
                    </div>
                    <button
                        onClick={() => fetchTasks(true)}
                        disabled={refreshing}
                        className="p-2 rounded-lg hover:bg-gray-100 transition-colors text-gray-400 hover:text-gray-700"
                        title="Refresh"
                    >
                        <RefreshCw size={16} className={refreshing ? 'animate-spin' : ''} />
                    </button>
                </div>

                {/* Overdue Tasks Toggle Tab */}
                <div className="flex items-center gap-2 mb-4 bg-gray-50 p-1 rounded-xl border border-gray-100 w-fit">
                    <button
                        onClick={() => setShowOverdue(false)}
                        className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${!showOverdue
                            ? 'bg-white text-gray-900 shadow-sm ring-1 ring-gray-200/50'
                            : 'text-gray-500 hover:text-gray-700'
                            }`}
                    >
                        Today's Missions
                    </button>
                    <button
                        onClick={() => setShowOverdue(true)}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all ${showOverdue
                            ? 'bg-red-50 text-red-700 shadow-sm ring-1 ring-red-200'
                            : 'text-gray-500 hover:text-gray-700'
                            }`}
                    >
                        <Clock size={14} className={showOverdue ? 'text-red-500' : 'text-gray-400'} />
                        Overdue Tasks
                        <span className={`px-1.5 py-0.5 rounded-full text-[10px] ml-1 ${showOverdue
                            ? 'bg-red-200/50 text-red-700'
                            : overdueTasks.length > 0
                                ? 'bg-red-100 text-red-600'
                                : 'bg-gray-200 text-gray-500'
                            }`}>
                            {overdueTasks.length}
                        </span>
                    </button>
                </div>

                {/* Progress */}
                <div className="space-y-2">
                    <div className="flex items-center justify-between">
                        <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Today's Progress</span>
                        <span className="text-sm font-bold text-gray-700">{doneCount}/{totalMissions} completed</span>
                    </div>
                    <div className="h-3 bg-gray-100 rounded-full overflow-hidden border border-gray-200">
                        <div
                            className="h-full rounded-full transition-all duration-700 ease-out"
                            style={{
                                width: `${progressPercent}%`,
                                background: progressPercent === 100
                                    ? 'linear-gradient(90deg, #22c55e, #16a34a)'
                                    : 'linear-gradient(90deg, #f97316, #ea580c)',
                            }}
                        />
                    </div>
                </div>
            </div>

            {/* ═══════════════════════════════════════ */}
            {/* OVERDUE LIST VIEW                      */}
            {/* ═══════════════════════════════════════ */}
            {showOverdue && (
                <div className="animate-fade-in">
                    {overdueTasks.length > 0 ? (
                        <>
                            <div className="bg-red-50 border border-red-100 rounded-2xl p-5 mb-5 flex items-start gap-3">
                                <AlertTriangle className="text-red-500 shrink-0 mt-0.5" size={20} />
                                <div>
                                    <h3 className="text-red-800 font-bold text-sm">You have {overdueTasks.length} overdue tasks!</h3>
                                    <p className="text-red-600/80 text-xs mt-0.5">These tasks were created on previous days and haven't been completed yet. Process them to keep your pipeline clean.</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {overdueTasks.map(task => (
                                    <TaskCard
                                        key={task.id}
                                        task={task}
                                        themeKey="hot"
                                        completing={completingIds.has(task.id)}
                                        onComplete={handleComplete}
                                        onExecute={handleExecute}
                                        onLeadClick={setSelectedLeadForModal}
                                    />
                                ))}
                            </div>
                        </>
                    ) : (
                        <div className="bg-white rounded-2xl border border-gray-200 p-10 sm:p-16 text-center shadow-sm">
                            <div className="flex justify-center mb-4">
                                <div className="w-16 h-16 rounded-2xl bg-green-50 border border-green-200 flex items-center justify-center">
                                    <PartyPopper size={32} className="text-green-500" />
                                </div>
                            </div>
                            <h2 className="text-xl font-bold text-gray-900 mb-2">No overdue tasks! 🎉</h2>
                            <p className="text-sm text-gray-500 max-w-sm mx-auto">
                                Excellent work! You haven't left any tasks behind from previous days.
                            </p>
                        </div>
                    )}
                </div>
            )}

            {/* ═══════════════════════════════════════ */}
            {/* ZERO INBOX                             */}
            {/* ═══════════════════════════════════════ */}
            {!showOverdue && allDone && (
                <div className="bg-white rounded-2xl border border-gray-200 p-10 sm:p-16 text-center shadow-sm">
                    <div className="flex justify-center mb-4">
                        <div className="w-16 h-16 rounded-2xl bg-green-50 border border-green-200 flex items-center justify-center">
                            {doneCount > 0
                                ? <Trophy size={32} className="text-green-500" />
                                : <PartyPopper size={32} className="text-green-500" />
                            }
                        </div>
                    </div>
                    <h2 className="text-xl font-bold text-gray-900 mb-2">
                        {doneCount > 0 ? 'All completed! 🏆' : 'Zero Inbox! 🎉'}
                    </h2>
                    <p className="text-sm text-gray-500 max-w-sm mx-auto">
                        {doneCount > 0
                            ? `You completed ${doneCount} tasks today. Excellent work!`
                            : 'No tasks generated. When AI identifies opportunities, they will appear here.'
                        }
                    </p>
                </div>
            )}

            {/* ═══════════════════════════════════════ */}
            {/* 3-COLUMN GRID TASK BOARD                */}
            {/* ═══════════════════════════════════════ */}
            {!showOverdue && !allDone && (
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

                    {/* COL 1: HOT (G4/G5) */}
                    <FeedSection
                        title="HOT (G4/G5)"
                        icon={<Flame size={15} />}
                        count={hotTasks.length}
                        themeKey="hot"
                        emptyText="No hot leads for today."
                    >
                        {hotTasks.map(task => (
                            <TaskCard
                                key={task.id}
                                task={task}
                                themeKey="hot"
                                completing={completingIds.has(task.id)}
                                onComplete={handleComplete}
                                onExecute={handleExecute}
                                onLeadClick={setSelectedLeadForModal}
                            />
                        ))}
                    </FeedSection>

                    {/* COL 2: MORNOS (G2/G3) */}
                    <FeedSection
                        title="MORNOS (G2/G3)"
                        icon={<TrendingUp size={15} />}
                        count={warmTasks.length}
                        themeKey="warm"
                        emptyText="No nurturing tasks."
                    >
                        {warmTasks.map(task => (
                            <TaskCard
                                key={task.id}
                                task={task}
                                themeKey="warm"
                                completing={completingIds.has(task.id)}
                                onComplete={handleComplete}
                                onExecute={handleExecute}
                                onLeadClick={setSelectedLeadForModal}
                            />
                        ))}
                    </FeedSection>

                    {/* COL 3: FRIOS (G1) */}
                    <FeedSection
                        title="FRIOS (G1)"
                        icon={<Snowflake size={15} />}
                        count={coldTasks.length}
                        themeKey="cold"
                        emptyText="No pending prospecting."
                        footer={
                            hiddenColdCount > 0 && !showAllCold ? (
                                <button
                                    onClick={() => setShowAllCold(true)}
                                    className="w-full py-3 text-center text-xs font-semibold text-blue-500 hover:text-blue-700 bg-blue-50 hover:bg-blue-100 border-t border-blue-200 transition-colors rounded-b-2xl"
                                >
                                    Show {hiddenColdCount} more tasks
                                </button>
                            ) : showAllCold && coldTasks.length > VISIBLE_COLD_CARDS ? (
                                <button
                                    onClick={() => setShowAllCold(false)}
                                    className="w-full py-3 text-center text-xs font-semibold text-gray-500 hover:text-gray-700 bg-gray-50 hover:bg-gray-100 border-t border-gray-200 transition-colors rounded-b-2xl"
                                >
                                    Show less
                                </button>
                            ) : null
                        }
                    >
                        {visibleColdTasks.map(task => (
                            <TaskCard
                                key={task.id}
                                task={task}
                                themeKey="cold"
                                completing={completingIds.has(task.id)}
                                onComplete={handleComplete}
                                onExecute={handleExecute}
                                onLeadClick={setSelectedLeadForModal}
                            />
                        ))}
                    </FeedSection>
                </div>
            )}
            {/* Unified Lead Modal */}
            {selectedLeadForModal && (
                <UnifiedLeadModal
                    lead={selectedLeadForModal}
                    onClose={() => setSelectedLeadForModal(null)}
                    onLeadUpdated={(updated) => {
                        setSelectedLeadForModal(prev => prev && prev.id === updated.id ? { ...prev, ...updated } : prev)
                    }}
                />
            )}
        </div>
    )
}

// ═══════════════════════════════════════════════
// COLUMN SECTION (3-Column Grid)
// ═══════════════════════════════════════════════

const FeedSection = ({ title, icon, count, themeKey, children, footer, emptyText }) => {
    const theme = COLUMN_THEMES[themeKey]
    const isEmpty = React.Children.count(children) === 0

    return (
        <div
            className="rounded-2xl overflow-hidden border border-gray-200 flex flex-col shadow-sm"
            style={{ background: '#ffffff' }}
        >
            {/* Gradient accent bar */}
            <div className="h-[3px] w-full shrink-0" style={{ background: theme.borderTop }} />

            {/* Header */}
            <div className={`flex items-center justify-between px-4 py-3 ${theme.headerBg} border-b ${theme.headerBorder}`}>
                <div className="flex items-center gap-2">
                    <span className={theme.iconColor}>{icon}</span>
                    <h3 className="text-xs font-bold text-gray-700 tracking-wider uppercase">
                        {title}
                    </h3>
                </div>
                <span className={`text-[11px] font-bold px-2.5 py-1 rounded-full ${theme.countBg} ${theme.countText} border ${theme.countBorder}`}>
                    {count}
                </span>
            </div>

            {/* Cards area with internal scroll */}
            <div
                className="flex-1 p-3 space-y-3 overflow-y-auto"
                style={{ maxHeight: '70vh', minHeight: '120px' }}
            >
                {isEmpty ? (
                    <div className={`flex items-center justify-center py-10 px-4 rounded-xl ${theme.emptyBg} border ${theme.emptyBorder}`}>
                        <p className="text-xs text-gray-500 text-center">{emptyText}</p>
                    </div>
                ) : children}
            </div>

            {/* Optional footer */}
            {footer}
        </div>
    )
}

