import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';

const AuthContext = createContext({});

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [profile, setProfile] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let mounted = true;

        // 1. Initial Session Check (Critical for F5/Refresh)
        const checkSession = async () => {
            try {
                const { data: { session } } = await supabase.auth.getSession();
                if (mounted && session?.user) {
                    setUser(session.user);
                    setLoading(false); // RELEASE LOADING IMMEDIATELY
                    fetchProfile(session.user.id, session.user.email); // Background fetch
                } else if (mounted) {
                    setLoading(false); // No session, stop loading
                }
            } catch (err) {
                console.error('Session check failed:', err);
                if (mounted) setLoading(false);
            }
        };

        checkSession();

        // 2. Auth State Listener
        const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
            if (!mounted) return;
            console.log('Auth State Change:', event);

            if (session?.user) {
                // If user changes or login happens, update state
                if (session.user.id !== user?.id) {
                    setUser(session.user);
                    setLoading(false); // RELEASE LOADING IMMEDIATELY
                    fetchProfile(session.user.id, session.user.email); // Background fetch
                }
            } else if (event === 'SIGNED_OUT') {
                setUser(null);
                setProfile(null);
                setLoading(false);
            }
        });

        // 3. Safety Timeout
        const safetyTimeout = setTimeout(() => {
            if (mounted && loading) {
                console.warn('Auth check timed out. Forcing stop loading.');
                setLoading(false);
            }
        }, 5000);

        return () => {
            mounted = false;
            clearTimeout(safetyTimeout);
            subscription.unsubscribe();
        };
    }, []); // Empty dependency array ok, relying on internal logic

    const fetchProfile = async (userId, userEmail) => {
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single();

            if (error) {
                // Self-healing attempt for missing profile
                if (error.code === 'PGRST116' && userEmail) {
                    console.log('Profile missing (PGRST116). Attempting to create default profile...');
                    const defaultProfile = {
                        id: userId,
                        email: userEmail,
                        role: 'client', // SECURITY: Default to client, never auto-elevate to admin
                        nome_empresa: 'Minha Agência'
                    };

                    const { error: insertError } = await supabase
                        .from('profiles')
                        .insert([defaultProfile]);

                    if (!insertError) {
                        setProfile(defaultProfile);
                        setLoading(false); // Success path
                        return;
                    }
                    console.error('Failed to create fallback profile:', insertError);
                }

                // 3. TRATAMENTO DE ERRO NO PERFIL (Strict Error Handling)
                // If we are here, we failed to get OR create a profile.
                console.error('Critical Profile Error provided. Signing out to prevent broken state.');
                await handleCriticalAuthError();
            } else {
                setProfile(data);
                setLoading(false); // Success path
            }
        } catch (error) {
            console.error('Profile fetch exception:', error);
            await handleCriticalAuthError();
        }
    };

    const handleCriticalAuthError = async () => {
        // Force sign out and clear state
        await supabase.auth.signOut();
        setProfile(null);
        setUser(null);
        setLoading(false); // GUARANTEED: Loading must stop
    };

    const signIn = async (email, password) => {
        const { data, error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });
        if (error) throw error;
        return data;
    };

    const signOut = async () => {
        try {
            await supabase.auth.signOut();
        } catch (error) {
            console.error('Error signing out:', error);
        } finally {
            // Force clear state to ensure UI updates immediately
            setUser(null);
            setProfile(null);
            setLoading(false);
        }
    };

    return (
        <AuthContext.Provider value={{ user, profile, loading, signIn, signOut }}>
            {!loading ? children : (
                <div style={{
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    height: '100vh',
                    flexDirection: 'column',
                    gap: '1rem',
                    background: '#f8fafc'
                }}>
                    <div style={{
                        width: '40px',
                        height: '40px',
                        border: '3px solid #e2e8f0',
                        borderTopColor: '#2563eb',
                        borderRadius: '50%',
                        animation: 'spin 1s linear infinite'
                    }}></div>
                    <span style={{ color: '#64748b', fontSize: '0.875rem' }}>Carregando Link&Lead...</span>
                </div>
            )}
            <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </AuthContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react'
import { supabase } from '../services/supabaseClient'

const ClientAuthContext = createContext({})

export const useClientAuth = () => useContext(ClientAuthContext)

export const ClientAuthProvider = ({ children }) => {
    const [clientUser, setClientUser] = useState(null)
    const [clientId, setClientId] = useState(null) // UUID
    const [clientLegacyId, setClientLegacyId] = useState(null) // Integer ID (Legacy)
    const [clientName, setClientName] = useState('')
    const [isTokenAuth, setIsTokenAuth] = useState(false)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        let mounted = true

        const fetchClientData = async (user) => {
            try {
                // 1. LOGIN (UUID) -> PERFIL
                const { data: profile, error } = await supabase
                    .from('profiles')
                    .select('id, client_id, role, nome_empresa') // Added nome_empresa and id
                    .eq('id', user.id)
                    .single()

                if (error) throw error

                if (profile.role !== 'client') {
                    console.warn('User found but role is not client:', profile.role)
                    setClientUser(null)
                    setClientId(null)
                    setClientLegacyId(null)
                    setClientName('')
                } else {
                    console.log(`Client Auth Success: User ${user.id} (UUID)`)
                    setClientUser(user)
                    setClientId(profile.id) // UUID PRIMARY
                    setClientLegacyId(profile.client_id) // Integer Legacy
                    setClientName(profile.nome_empresa || '')
                }
            } catch (err) {
                console.error('Error fetching client profile:', err)
                setClientUser(null)
                setClientId(null)
                setClientLegacyId(null)
                setClientName('')
            } finally {
                if (mounted) setLoading(false)
            }
        }

        const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
            if (isTokenAuth) return // Don't override if manually logged in via token

            if (session?.user) {
                fetchClientData(session.user)
            } else {
                setClientUser(null)
                setClientId(null)
                setClientLegacyId(null)
                setClientName('')
                setLoading(false)
            }
        })

        return () => {
            mounted = false
            subscription.unsubscribe()
        }
    }, [isTokenAuth]) // Re-run if token auth state changes (though mainly to re-bind listener logic)

    const loginWithToken = async (token) => {
        setLoading(true)
        try {
            // Check 'clients' table for access_token
            const { data: client, error } = await supabase
                .from('clients')
                .select('*')
                .eq('access_token', token)
                .single()

            if (error || !client) {
                throw new Error('Token inválido ou expirado.')
            }

            // Set global state "as if" logged in
            // Mocking a clientUser object to satisfy existence checks
            setClientUser({ id: 'token_user', email: 'token_access', role: 'client' })

            // Use client.id directly. 
            // Note: If 'tabela_projetofred1' uses UUID from profiles, this might miss-match unless client.id IS the UUID.
            // Assuming client.id is the correct identifier for posts in this context.
            setClientId(client.id)
            setClientLegacyId(client.id) // Assuming same ID or fallback
            // FIX: User confirmed 'clients' table uses 'name' column.
            setClientName(client.name || client.nome_empresa)
            setIsTokenAuth(true)

            return true
        } catch (err) {
            console.error(err)
            return false
        } finally {
            setLoading(false)
        }
    }

    const signOut = async () => {
        if (isTokenAuth) {
            setIsTokenAuth(false)
            setClientUser(null)
            setClientId(null)
            setClientLegacyId(null)
            setClientName('')
        } else {
            await supabase.auth.signOut()
            setClientUser(null)
            setClientId(null)
            setClientLegacyId(null)
            setClientName('')
        }
    }

    return (
        <ClientAuthContext.Provider value={{ clientUser, clientId, clientLegacyId, clientName, loading, signOut, isTokenAuth, loginWithToken }}>
            {children}
        </ClientAuthContext.Provider>
    )
}

import React, { createContext, useContext, useState, useEffect } from 'react'

const ClientSelectionContext = createContext()

export const useClientSelection = () => {
    return useContext(ClientSelectionContext)
}

export const ClientSelectionProvider = ({ children }) => {
    const [selectedClientId, setSelectedClientId] = useState(() => {
        // Persist selection
        const saved = localStorage.getItem('selectedClientId')
        return saved ? JSON.parse(saved) : null
    })

    // Track which lead is currently open in the Inbox (used by notification system)
    const [activeLeadId, setActiveLeadId] = useState(null)

    const setClient = (clientId) => {
        setSelectedClientId(clientId)
        if (clientId) {
            localStorage.setItem('selectedClientId', JSON.stringify(clientId))
        } else {
            localStorage.removeItem('selectedClientId')
        }
    }

    const value = {
        selectedClientId,
        setSelectedClientId: setClient,
        activeLeadId,
        setActiveLeadId
    }

    return (
        <ClientSelectionContext.Provider value={value}>
            {children}
        </ClientSelectionContext.Provider>
    )
}

import React, { createContext, useContext, useState, useEffect } from 'react'
import { supabase } from '../services/supabaseClient'
import { useAuth } from './AuthContext'

const TeamMemberContext = createContext({ teamRole: null, teamId: null, isTeamAdmin: false, loading: true })

export const useTeamMember = () => useContext(TeamMemberContext)

export const TeamMemberProvider = ({ children }) => {
    const { user } = useAuth()
    const [teamRole, setTeamRole] = useState(null)
    const [teamId, setTeamId] = useState(null)
    const [loading, setLoading] = useState(true)

    useEffect(() => {
        if (!user) {
            setTeamRole(null)
            setTeamId(null)
            setLoading(false)
            return
        }

        const fetchTeamMembership = async () => {
            try {
                // Use maybeSingle() instead of single() so it never throws on 0 rows
                const { data, error } = await supabase
                    .from('team_members')
                    .select('role, team_id')
                    .eq('user_id', user.id)
                    .eq('role', 'team_admin')   // Only care about admin rows
                    .maybeSingle()

                if (error) {
                    console.error('[TeamMemberContext] DB error:', error.message)
                    setTeamRole(null)
                    setTeamId(null)
                } else {
                    console.log('[TeamMemberContext] ROLE RECUPERADA DO BANCO:', data?.role ?? 'null — nenhuma linha team_admin encontrada')
                    setTeamRole(data?.role ?? null)
                    setTeamId(data?.team_id ?? null)
                }
            } catch (err) {
                console.error('[TeamMemberContext] Exceção inesperada:', err)
                setTeamRole(null)
                setTeamId(null)
            } finally {
                setLoading(false)
            }
        }

        fetchTeamMembership()
    }, [user])

    return (
        <TeamMemberContext.Provider value={{
            teamRole,
            teamId,
            isTeamAdmin: teamRole === 'team_admin',
            loading
        }}>
            {children}
        </TeamMemberContext.Provider>
    )
}

import React, { useState, useEffect, useMemo, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '../services/supabaseClient'
import { useAuth } from '../contexts/AuthContext'
import { useClientSelection } from '../contexts/ClientSelectionContext'
import { KpiCardSkeleton, HeroTaskCardSkeleton, Skeleton } from '../components/Skeleton'
import LeadAvatar from '../components/LeadAvatar'
import UnifiedLeadModal from '../components/UnifiedLeadModal'
import {
    Crosshair,
    Flame,
    Trophy,
    PartyPopper,
    Loader2,
    RefreshCw,
    TrendingUp,
    Users,
    HandMetal,
    MessageCircle,
    CheckCircle2,
    Zap,
    Star
} from 'lucide-react'

// ═══════════════════════════════════════════════
// CONSTANTS
// ═══════════════════════════════════════════════

const HOT_STAGES = ['G4', 'G5']

// Light theme cadence styles
const CADENCE_STYLES = {
    G1: 'bg-gray-100 text-gray-600 border-gray-300',
    G2: 'bg-blue-50 text-blue-600 border-blue-200',
    G3: 'bg-cyan-50 text-cyan-700 border-cyan-200',
    G4: 'bg-orange-50 text-orange-600 border-orange-200',
    G5: 'bg-red-50 text-red-600 border-red-200',
}

// ═══════════════════════════════════════════════
// MAIN COMPONENT — ADMIN PANEL (Command Center)
// ═══════════════════════════════════════════════

const AdminPanel = () => {
    const { user, profile } = useAuth()
    const { selectedClientId } = useClientSelection()

    const [loading, setLoading] = useState(true)
    const [refreshing, setRefreshing] = useState(false)
    const [stats, setStats] = useState({
        doneToday: 0,
        pendingTotal: 0,
        hotLeads: 0
    })
    const [criticalTasks, setCriticalTasks] = useState([])
    const [radarLeads, setRadarLeads] = useState([])
    const [completingIds, setCompletingIds] = useState(new Set())
    const [selectedLeadForModal, setSelectedLeadForModal] = useState(null)

    // ───────────────────────────────────────────
    // DATA FETCHING
    // ───────────────────────────────────────────

    const fetchData = useCallback(async (isRefresh = false) => {
        if (!user?.id) return
        if (isRefresh) setRefreshing(true)
        else setLoading(true)

        try {
            const todayStart = new Date()
            todayStart.setHours(0, 0, 0, 0)
            const todayStr = todayStart.toISOString()
            const dateStr = new Date().toISOString().split('T')[0]

            // 1. Stats: Done Today
            let doneQuery = supabase
                .from('tasks')
                .select('id, leads!inner(client_id)', { count: 'exact', head: true })
                .neq('leads.is_blacklisted', true)
                .eq('status', 'COMPLETED')
                .gte('completed_at', `${dateStr}T00:00:00`)

            if (selectedClientId) {
                doneQuery = doneQuery
                    .eq('client_id', selectedClientId)
                    .eq('leads.client_id', selectedClientId)
            }

            // 2. Pending Tasks (Top 30 for today, same as Cockpit)
            let pendingQuery = supabase
                .from('tasks')
                .select('*, leads!inner(id, client_id, nome, empresa, headline, linkedin_profile_url, cadence_stage, total_interactions_count, avatar_url, icp_score)')
                .neq('leads.is_blacklisted', true)
                .eq('status', 'PENDING')
                .gte('created_at', todayStr)
                .order('created_at', { ascending: true })
                .limit(30)

            if (selectedClientId) {
                pendingQuery = pendingQuery
                    .eq('client_id', selectedClientId)
                    .eq('leads.client_id', selectedClientId)
            }

            // 3. Radar Leads (Responding/Hot)
            let radarQuery = supabase
                .from('leads')
                .select('id, nome, empresa, headline, cadence_stage, total_interactions_count, updated_at, linkedin_profile_url, avatar_url')
                .neq('is_blacklisted', true)
                .gt('total_interactions_count', 0)
                .order('updated_at', { ascending: false })
                .limit(10)

            if (selectedClientId) radarQuery = radarQuery.eq('client_id', selectedClientId)

            // Execute all
            const [doneRes, tasksRes, radarRes] = await Promise.all([
                doneQuery,
                pendingQuery,
                radarQuery
            ])

            if (tasksRes.error) throw tasksRes.error
            if (radarRes.error) throw radarRes.error

            const allPending = tasksRes.data || []

            // Sort: highest Cadence first (G5 -> G1), then ICP score. Foco Total will pick the top 3.
            const STAGE_PRIORITY = { G5: 0, G4: 1, G3: 2, G2: 3, G1: 4 }
            const ICP_PRIORITY = { A: 1, B: 2, C: 3 }

            const sortedPriority = [...allPending].sort((a, b) => {
                const sa = STAGE_PRIORITY[a.leads?.cadence_stage] ?? 5
                const sb = STAGE_PRIORITY[b.leads?.cadence_stage] ?? 5
                if (sa !== sb) return sa - sb

                const ia = ICP_PRIORITY[a.leads?.icp_score] ?? 4
                const ib = ICP_PRIORITY[b.leads?.icp_score] ?? 4
                if (ia !== ib) return ia - ib

                return new Date(a.created_at) - new Date(b.created_at)
            })

            const focusTasks = sortedPriority.slice(0, 3)

            const g4g5 = allPending.filter(t => HOT_STAGES.includes(t.leads?.cadence_stage))

            setStats({
                doneToday: doneRes.count || 0,
                pendingTotal: allPending.length,
                hotLeads: g4g5.length
            })

            setCriticalTasks(focusTasks)
            setRadarLeads(radarRes.data || [])

        } catch (err) {
            console.error('Error fetching command center data:', err)
        } finally {
            setLoading(false)
            setRefreshing(false)
        }
    }, [user?.id, selectedClientId])

    useEffect(() => {
        fetchData()
    }, [fetchData])

    // ───────────────────────────────────────────
    // ACTIONS
    // ───────────────────────────────────────────

    const handleComplete = async (taskId) => {
        setCompletingIds(prev => new Set(prev).add(taskId))

        // Optimistic update
        setCriticalTasks(prev => prev.filter(t => t.id !== taskId))
        setStats(prev => ({
            ...prev,
            doneToday: prev.doneToday + 1,
            pendingTotal: Math.max(0, prev.pendingTotal - 1)
        }))

        try {
            const { error } = await supabase
                .from('tasks')
                .update({ status: 'COMPLETED', completed_at: new Date().toISOString() })
                .eq('id', taskId)

            if (error) throw error
        } catch (err) {
            console.error('Error completing task:', err)
            fetchData(true) // Revert on error
        } finally {
            setCompletingIds(prev => {
                const next = new Set(prev)
                next.delete(taskId)
                return next
            })
        }
    }

    const navigate = useNavigate()

    const handleExecute = (leadId) => {
        if (leadId) {
            navigate(`/sales/inbox?leadId=${leadId}`)
        }
    }

    const getGreeting = () => {
        const hour = new Date().getHours()
        if (hour < 12) return 'Good morning'
        if (hour < 18) return 'Good afternoon'
        return 'Good evening'
    }

    const progressPercent = useMemo(() => {
        const total = stats.doneToday + stats.pendingTotal
        if (total === 0) return 0
        return Math.round((stats.doneToday / total) * 100)
    }, [stats])

    // ───────────────────────────────────────────
    // RENDER
    // ───────────────────────────────────────────

    if (loading) {
        return (
            <div className="min-h-screen bg-gray-50 text-gray-900 p-4 sm:p-6 lg:p-8">
                <div className="max-w-6xl mx-auto space-y-6">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Skeleton className="w-10 h-10 rounded-xl" />
                            <div className="space-y-2">
                                <Skeleton className="w-48 h-8" />
                                <Skeleton className="w-64 h-4" />
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <Skeleton className="h-32 rounded-2xl" />
                        <div className="col-span-2 grid grid-cols-3 gap-4">
                            <KpiCardSkeleton />
                            <KpiCardSkeleton />
                            <KpiCardSkeleton />
                        </div>
                    </div>

                    <div className="space-y-4">
                        <Skeleton className="w-32 h-6" />
                        <div className="space-y-3">
                            <HeroTaskCardSkeleton />
                            <HeroTaskCardSkeleton />
                            <HeroTaskCardSkeleton />
                        </div>
                    </div>
                </div>
            </div>
        )
    }

    return (
        <div className="min-h-screen bg-gray-50 text-gray-900 p-4 sm:p-6 lg:p-8">
            <div className="max-w-6xl mx-auto space-y-6">

                {/* Header */}
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-xl bg-orange-50 border border-orange-200 flex items-center justify-center">
                            <Crosshair size={20} className="text-orange-500" />
                        </div>
                        <div>
                            <h1 className="text-2xl sm:text-3xl font-bold tracking-tight text-gray-900">
                                {getGreeting()}, {profile?.name?.split(' ')[0] || 'Commander'} 🎯
                            </h1>
                            <p className="text-sm text-gray-500">Command Center · Where you make money right now</p>
                        </div>
                    </div>
                    <button
                        onClick={() => fetchData(true)}
                        className="p-2 text-gray-400 hover:text-orange-500 hover:bg-orange-50 rounded-lg transition-colors"
                        disabled={refreshing}
                    >
                        <RefreshCw size={20} className={refreshing ? 'animate-spin' : ''} />
                    </button>
                </div>

                {/* PLACAR DO DIA */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    {/* Ring Chart */}
                    <div className="bg-white rounded-2xl border border-gray-200 p-6 flex items-center justify-between relative overflow-hidden">
                        <div className="relative z-10">
                            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wider mb-1">Daily Goal</h3>
                            <div className="flex items-baseline gap-1">
                                <span className="text-4xl font-bold text-gray-900">{progressPercent}%</span>
                                <span className="text-sm text-gray-400">completed</span>
                            </div>
                        </div>
                        <ProgressRing percent={progressPercent} size={80} stroke={6} />
                    </div>

                    {/* Stats */}
                    <div className="col-span-2 grid grid-cols-3 gap-4">
                        <KpiCard
                            icon={<CheckCircle2 size={18} />}
                            label="Completed Today"
                            value={stats.doneToday}
                            accent="text-green-600"
                        />
                        <KpiCard
                            icon={<Loader2 size={18} />}
                            label="Pending"
                            value={stats.pendingTotal}
                            accent="text-gray-900"
                        />
                        <KpiCard
                            icon={<Flame size={18} />}
                            label="Hot Leads"
                            value={stats.hotLeads}
                            accent="text-orange-500"
                        />
                    </div>
                </div>

                {/* FOCO TOTAL (HERO SECTION) */}
                <div>
                    <div className="flex items-center gap-2 mb-4">
                        <Zap className="text-orange-500" size={20} />
                        <h2 className="text-lg font-bold text-gray-900">Total Focus</h2>
                        <span className="text-xs font-medium px-2 py-0.5 rounded-full bg-orange-100 text-orange-700 border border-orange-200">
                            Maximum Priority
                        </span>
                    </div>

                    {criticalTasks.length > 0 ? (
                        <div className="space-y-3">
                            {criticalTasks.map((task, idx) => (
                                <HeroTaskCard
                                    key={task.id}
                                    task={task}
                                    index={idx}
                                    completing={completingIds.has(task.id)}
                                    onComplete={handleComplete}
                                    onExecute={handleExecute}
                                    onLeadClick={setSelectedLeadForModal}
                                />
                            ))}
                        </div>
                    ) : (
                        <div className="bg-white rounded-2xl border border-gray-200 p-8 text-center flex flex-col items-center justify-center dashed-border">
                            <div className="w-12 h-12 bg-green-50 rounded-full flex items-center justify-center mb-3">
                                <PartyPopper className="text-green-500" size={24} />
                            </div>
                            <h3 className="text-gray-900 font-bold mb-1">All clear here!</h3>
                            <p className="text-gray-500 text-sm">No critical tasks pending at the moment.</p>
                        </div>
                    )}
                </div>

                {/* RADAR DE OPORTUNIDADES */}
                <div>
                    <div className="flex items-center justify-between mb-4">
                        <div className="flex items-center gap-2">
                            <TrendingUp className="text-blue-500" size={20} />
                            <h2 className="text-lg font-bold text-gray-900">Opportunity Radar</h2>
                        </div>
                    </div>

                    <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x -mx-4 px-4 sm:mx-0 sm:px-0">
                        {radarLeads.length > 0 ? (
                            radarLeads.map(lead => (
                                <RadarLeadCard key={lead.id} lead={lead} onLeadClick={setSelectedLeadForModal} />
                            ))
                        ) : (
                            <div className="text-sm text-gray-400 italic p-4">No recent activity on the radar.</div>
                        )}
                    </div>
                </div>

            </div>

            {/* Quick Actions Bar (Bottom) */}
            <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-md border border-gray-200 shadow-xl rounded-full px-6 py-3 flex items-center gap-4 z-50">
                <button
                    onClick={() => navigate('/campaigns')}
                    className="flex items-center gap-2 text-sm font-semibold text-gray-600 hover:text-orange-600 transition-colors"
                >
                    <Users size={16} />
                    New Manual Lead
                </button>
                <div className="w-px h-4 bg-gray-300" />
                <button
                    onClick={() => navigate('/missions')}
                    className="flex items-center gap-2 text-sm font-bold text-orange-600 hover:text-orange-700 transition-colors"
                >
                    <Trophy size={16} />
                    Open Full Daily Tasks
                </button>
            </div>
            {/* Unified Lead Modal */}
            {selectedLeadForModal && (
                <UnifiedLeadModal
                    lead={selectedLeadForModal}
                    onClose={() => setSelectedLeadForModal(null)}
                    onLeadUpdated={(updated) => {
                        setSelectedLeadForModal(prev => prev && prev.id === updated.id ? { ...prev, ...updated } : prev)
                    }}
                />
            )}
        </div>
    )
}

