const ClientInsightsPage = () => {
    // Legacy/Context access (still used for Admin Emulation or Standard Login)
    const { clientId: contextId, clientLegacyId, clientName: contextName } = useClientAuth()

    const [posts, setPosts] = useState([])
    const [questions, setQuestions] = useState([])
    const [status, setStatus] = useState('loading') // 'loading', 'success', 'error'
    const [errorMessage, setErrorMessage] = useState('')
    const [clientData, setClientData] = useState(null) // Local client data for Magic Link

    const [selectedQuestion, setSelectedQuestion] = useState(null)
    const [selectedPost, setSelectedPost] = useState(null)

    // "RADICAL SIMPLIFICATION" - Single Load Logic
    useEffect(() => {
        let isMounted = true

        const carregarDados = async () => {
            // 1. Detect Token Mode
            const pathname = window.location.pathname;
            const isMagicLink = pathname.includes('/portal/') && !pathname.includes('insights') && !pathname.includes('login');

            if (!isMagicLink) {
                // Not Magic Link -> Standard Context logic
                if (contextName && status !== 'success') {
                    // Check if context has valid data
                    supabase.from('tabela_projetofred1')
                        .select('*')
                        .eq('nome_cliente', contextName)
                        .order('created_at', { ascending: false })
                        .range(0, 49) // Paginação Auto (Limit 50)
                        .then(({ data }) => {
                            if (isMounted) {
                                setPosts(data || [])
                                setClientData({ name: contextName })
                                setStatus('success')
                            }
                        })
                }
                return;
            }

            console.log("Iniciando carga única segura (RPC)...");
            const token = pathname.split('/').pop();

            // 2. Chamada à função RPC Segura
            const { data: portalData, error: portalError } = await supabase
                .rpc('get_portal_data', { p_token: token });

            if (portalError || !portalData || portalData.error) {
                console.error("Erro no Portal:", portalError || portalData?.error);
                if (isMounted) {
                    setStatus('error');
                    setErrorMessage(portalData?.error || "Link inválido ou expirado.");
                }
                return;
            }

            // 3. Mapeamento de Estado
            if (isMounted) {
                setClientData(portalData.client);
                setPosts(portalData.posts || []);
                setQuestions(portalData.questions || []);
                setStatus('success');
            }
        };

        carregarDados();

        return () => {
            isMounted = false
        }
    }, [contextName]); // Dependency on contextName helps trigger standard auth load if needed

    // --- HELPERS ---
    const handlePostReview = async (postId, status, comment) => {
        const { error } = await supabase.from('tabela_projetofred1').update({ status }).eq('id', postId)
        if (!error) {
            setPosts(prev => prev.map(p => p.id === postId ? { ...p, status } : p))
            if (status === 'aprovado') alert("Post aprovado com sucesso! 🚀")
        }
    }
    const handleQuestionResponse = (qId) => setQuestions(prev => prev.filter(q => q.id !== qId))
    const getStatusStyle = (status) => {
        const s = (status || '').toUpperCase()
        if (s === 'WAITING_APPROVAL' || s === 'PENDING') return { bg: '#fef3c7', color: '#b45309', label: 'Aguardando Aprovação', icon: <Clock size={12} /> }
        if (s === 'APPROVED' || s === 'APROVADO') return { bg: '#dcfce7', color: '#166534', label: 'Aprovado', icon: <CheckCircle2 size={12} /> }
        if (s === 'CHANGES_REQUESTED' || s.includes('REVI')) return { bg: '#f3e8ff', color: '#7e22ce', label: 'Alteração Solicitada', icon: <Mic size={12} /> }
        if (s === 'POSTADO') return { bg: '#e0f2fe', color: '#0369a1', label: 'Publicado', icon: <Send size={12} /> }
        return { bg: '#f1f5f9', color: '#64748b', label: 'Status: ' + status, icon: <AlertCircle size={12} /> }
    }

    // MOVED TO TOP LEVEL SCOPE

    if (status === 'loading') {
        return (
            <div style={{ padding: '4rem', textAlign: 'center', color: '#64748b' }}>
                <h1>Carregando Portal... <Loader2 className="animate-spin inline ml-2" /></h1>
            </div>
        )
    }

    if (status === 'error') {
        return (
            <div style={{ padding: '4rem', textAlign: 'center' }}>
                <h1 style={{ color: '#ef4444' }}>Erro: {errorMessage}</h1>
            </div>
        )
    }

    // --- Filtering Logic ---
    const pendingPosts = posts.filter(p => {
        const s = (p.status || '').toUpperCase()
        return (s === 'WAITING_APPROVAL' || s === 'CHANGES_REQUESTED') && s !== 'POSTADO'
    })

    const scheduledPosts = posts.filter(p => {
        const s = (p.status || '').toUpperCase()
        return (s === 'APPROVED' || s === 'AGENDADO' || s === 'APROVADO') && s !== 'POSTADO'
    })

    const displayName = clientData?.name || contextName || 'Cliente';

    // SUCCESS RENDER
    return (
        <div className="insights-container">
            <style>{pageStyles}</style>

            {/* Header */}
            <div className="insights-header">
                <h1>Olá, {displayName}</h1>
                <p>
                    Você tem <span className="highlight-stats">{questions.length} perguntas pendentes</span> e <span className="highlight-stats">{posts.length} posts</span> na sua galeria.
                </p>
            </div>

            {/* Section: Posts Grid (MOVED TO TOP) */}
            {/* --- SEÇÃO: POSTAGENS PENDENTES --- */}
            <div className="mb-12">
                <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
                    <div className="w-2 h-8 bg-orange-500 rounded-full"></div>
                    Postagens Pendentes ({pendingPosts.length})
                </h2>

                <div className="flex flex-col gap-3">
                    {pendingPosts.length > 0 ? (
                        pendingPosts.map(post => (
                            <div key={post.id} className="bg-white border border-gray-200 rounded-lg p-4 flex items-center justify-between shadow-sm hover:shadow-md transition-all">
                                <div className="flex-1 pr-4">
                                    <h3 className="font-semibold text-gray-800 text-lg mb-1 line-clamp-1">{post.tema || 'Sem Título'}</h3>
                                    <p className="text-sm text-gray-500 flex items-center gap-2">
                                        <Clock size={14} />
                                        {post.data_criacao ? new Date(post.data_criacao).toLocaleDateString('en-US') : 'Data N/A'}
                                        <span className="text-xs bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-medium ml-2">
                                            {getStatusStyle(post.status).label}
                                        </span>
                                    </p>
                                </div>
                                <button
                                    onClick={() => window.location.href = `/post-feedback/${post.id}`}
                                    className="bg-gray-900 text-white px-6 py-2 rounded-lg font-medium text-sm hover:bg-gray-800 transition-colors shrink-0"
                                >
                                    Verificar
                                </button>
                            </div>
                        ))
                    ) : (
                        <div className="text-center py-8 bg-gray-50 rounded-lg border border-dashed border-gray-300">
                            <p className="text-gray-500">Nenhuma postagem pendente no momento.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* --- SEÇÃO: POSTAGENS AGENDADAS / APROVADAS --- */}
            <div style={{ marginBottom: '4rem' }}>
                <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center gap-2">
                    <div className="w-2 h-8 bg-green-500 rounded-full"></div>
                    Postagens Agendadas ({scheduledPosts.length})
                </h2>

                <div className="flex flex-col gap-3">
                    {scheduledPosts.length > 0 ? (
                        scheduledPosts.map(post => (
                            <div key={post.id} className="bg-white border border-gray-200 rounded-lg p-4 flex items-center justify-between shadow-sm hover:shadow-md transition-all">
                                <div className="flex-1 pr-4">
                                    <h3 className="font-semibold text-gray-800 text-lg mb-1 line-clamp-1">{post.tema || 'Sem Título'}</h3>
                                    <p className="text-sm text-gray-500 flex items-center gap-2">
                                        <CalendarClock size={14} />
                                        {post.data_agendamento ? new Date(post.data_agendamento).toLocaleDateString('en-US') : 'Agendamento N/A'}
                                        <span className="text-xs bg-green-100 text-green-700 px-2 py-0.5 rounded-full font-medium ml-2">
                                            {getStatusStyle(post.status).label}
                                        </span>
                                    </p>
                                </div>
                                <button
                                    onClick={() => window.location.href = `/post-feedback/${post.id}`}
                                    className="bg-white border border-gray-300 text-gray-700 px-6 py-2 rounded-lg font-medium text-sm hover:bg-gray-50 transition-colors shrink-0"
                                >
                                    Ver Detalhes
                                </button>
                            </div>
                        ))
                    ) : (
                        <div className="text-center py-8 bg-gray-50 rounded-lg border border-dashed border-gray-300">
                            <p className="text-gray-500">Nenhuma postagem agendada no momento.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Section: Questions (Pending) */}
            {questions.length > 0 && (
                <div style={{ marginBottom: '4rem' }}>
                    <h3 style={{ fontSize: '1.25rem', fontWeight: 700, color: '#334155', marginBottom: '1.5rem', display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <Mic size={20} /> Perguntas Pendentes
                    </h3>
                    <div className="questions-list">
                        {questions.map(q => (
                            <div key={q.id} className="question-item">
                                <div style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
                                    <div style={{ background: '#fef3c7', padding: '0.75rem', borderRadius: '50%', color: '#d97706' }}>
                                        <MessageSquare size={20} />
                                    </div>
                                    <div>
                                        <p style={{ fontWeight: 600, color: '#1e293b', marginBottom: '4px' }}>{q.question_text}</p>
                                        <span style={{ fontSize: '0.875rem', color: '#64748b' }}>Aguardando sua resposta</span>
                                    </div>
                                </div>
                                <button
                                    onClick={() => setSelectedQuestion(q)}
                                    style={{ padding: '0.75rem 1.5rem', background: '#7c3aed', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' }}
                                >
                                    Responder <ChevronRight size={16} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Section: Content Calendar (MOVED TO BOTTOM) */}
            {posts.length > 0 && (
                <ContentCalendar posts={posts} />
            )}

            {/* Modals */}
            {selectedQuestion && <QuestionResponseModal question={selectedQuestion} onClose={() => setSelectedQuestion(null)} onResponseSent={handleQuestionResponse} />}
            {selectedPost && <PostReviewModal post={selectedPost} onClose={() => setSelectedPost(null)} onReview={handlePostReview} />}
        </div >
    )
}

export default ClientInsightsPage

import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { useAuth } from '../contexts/AuthContext'; // Import Auth
import { Pencil, Upload, FileText, X, Check, Link as LinkIcon, Info, AlertTriangle, Linkedin, Download } from 'lucide-react';



export default function ClientsPage() {
    const { user, profile } = useAuth(); // Hook Auth
    const [clients, setClients] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [saving, setSaving] = useState(false);
    const [editingClient, setEditingClient] = useState(null);
    const [toast, setToast] = useState(null);

    // File Upload State
    const [filesToUpload, setFilesToUpload] = useState([]);
    const [existingFiles, setExistingFiles] = useState([]);

    const [formData, setFormData] = useState({
        name: '',
        email_contato: '',
        description: '',
        tone_of_voice: 'Profissional',
        target_audience_default: '',
        pain_points: '',
        unipile_account_id: ''
    });

    useEffect(() => {
        fetchClients();
    }, []);

    async function fetchClients() {
        try {
            setLoading(true);
            // SECURITY: Filter by owner unless admin
            let query = supabase.from('clients').select('*');
            
            if (profile?.role !== 'admin') {
                query = query.eq('auth_user_id', user.id);
            }

            const { data, error } = await query.order('created_at', { ascending: false });
            if (error) throw error;
            setClients(data || []);
        } catch (error) {
            console.error('Error fetching clients:', error);
        } finally {
            setLoading(false);
        }
    }

    async function fetchClientFiles(clientId) {
        try {
            const { data, error } = await supabase
                .storage
                .from('client-docs')
                .list(`core-docs/${clientId}`, { limit: 50 });

            if (error) throw error;
            const files = (data || []).filter(f => f.name !== '.emptyFolderPlaceholder');
            setExistingFiles(files);
        } catch (error) {
            console.error('Error fetching client files:', error);
            setExistingFiles([]);
        }
    }

    const handleDownloadFile = async (fileName) => {
        if (!editingClient) return;
        const filePath = `core-docs/${editingClient.id}/${fileName}`;
        const { data, error } = await supabase
            .storage
            .from('client-docs')
            .createSignedUrl(filePath, 60);

        if (error) {
            console.error('Error generating download link:', error);
            alert('Error downloading file.');
            return;
        }
        window.open(data.signedUrl, '_blank');
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: value
        }));
    };

    const handleFileChange = (e) => {
        if (e.target.files && e.target.files.length > 0) {
            const newFiles = Array.from(e.target.files);
            setFilesToUpload(prev => [...prev, ...newFiles]);
        }
    };

    const removeFileToUpload = (index) => {
        setFilesToUpload(prev => prev.filter((_, i) => i !== index));
    };

    const handleEdit = (client) => {
        setEditingClient(client);
        setFormData({
            name: client.name || '',
            email_contato: client.email_contato || '',
            description: client.description || '',
            tone_of_voice: client.tone_of_voice || 'Profissional',
            target_audience_default: client.target_audience_default || '',
            pain_points: client.pain_points || '',
            unipile_account_id: client.unipile_account_id || ''
        });
        setFilesToUpload([]);
        setExistingFiles([]);
        fetchClientFiles(client.id);
        setShowModal(true);
    };

    const handleNew = () => {
        setEditingClient(null);
        setFormData({
            name: '',
            email_contato: '',
            description: '',
            tone_of_voice: 'Profissional',
            target_audience_default: '',
            pain_points: '',
            unipile_account_id: ''
        });
        setFilesToUpload([]);
        setExistingFiles([]);
        setShowModal(true);
    };

    const handleDelete = async () => {
        if (!editingClient || !window.confirm('Are you sure you want to delete this client? This action cannot be undone.')) return;

        setSaving(true);
        try {
            const { error } = await supabase
                .from('clients')
                .delete()
                .eq('id', editingClient.id);

            if (error) throw error;

            setShowModal(false);
            fetchClients();
            alert('Client successfully deleted!');
        } catch (error) {
            console.error('Error deleting:', error);
            alert('Error deleting: ' + error.message);
        } finally {
            setSaving(false);
        }
    };

    const handleCopyLink = (client) => {
        if (!client.access_token) {
            alert("This client does not have an access token.");
            return;
        }
        const link = `${window.location.origin}/portal/${client.access_token}`;
        navigator.clipboard.writeText(link);

        setToast({ message: "Access link copied!", type: "success" });
        setTimeout(() => setToast(null), 3000);
    };

    const sanitizeFileName = (originalName) => {
        return originalName.replace(/[^a-zA-Z0-9.]/g, '_');
    };

    const uploadFiles = async (clientId) => {
        if (!filesToUpload || filesToUpload.length === 0) return null;

        const file = filesToUpload[0];
        if (!file) return null;

        const safeName = sanitizeFileName(file.name);
        const filePath = `core-docs/${clientId}/${safeName}`;

        console.log(`[DEBUG] Uploading ${file.name} to Supabase Storage: ${filePath}`);

        const { data: uploadData, error: uploadError } = await supabase
            .storage
            .from('client-docs')
            .upload(filePath, file, { upsert: true });

        if (uploadError) {
            console.error('[DEBUG] Upload error:', uploadError);
            throw new Error(`Upload failed: ${uploadError.message}`);
        }

        console.log('[DEBUG] Upload complete:', uploadData);
        return uploadData.path;
    };

    const handleSubmit = async (e) => {
        e.preventDefault(); // 1. Prevent Default
        setSaving(true);

        try {

            // PAYLOAD CONSTRUCTION & LOGGING
            const payload = {
                name: formData.name,
                email_contato: formData.email_contato,
                description: formData.description,
                tone_of_voice: formData.tone_of_voice,
                target_audience_default: formData.target_audience_default,
                pain_points: formData.pain_points,
                unipile_account_id: formData.unipile_account_id,
                auth_user_id: user.id // SECURITY: Associate client with the creator
            };

            // --- EXECUTE SUPABASE CALLS AFTER PAYLOAD IS READY ---
            let clientData = null;
            let realClientId = null;

            if (editingClient) {
                const { data, error } = await supabase
                    .from('clients')
                    .update(payload) // Use the constructed payload
                    .eq('id', editingClient.id)
                    .select()
                    .single();

                if (error) throw error;
                clientData = data;
            } else {
                const { data, error } = await supabase
                    .from('clients')
                    .insert([payload]) // Use the constructed payload
                    .select()
                    .single();

                if (error) throw error;
                clientData = data;
            }

            // SAFETY CHECKS
            if (!clientData) throw new Error("Critical error: Client data did not return from database.");
            realClientId = clientData.id;
            console.log("[DEBUG] Captured numeric ID:", realClientId);
            if (!realClientId) throw new Error("Critical error: Client ID is invalid.");

            // UPLOAD + UPDATE core_doc_id
            if (filesToUpload.length > 0) {
                console.log(`[DEBUG] Starting upload for ID: ${realClientId}`);
                const docPath = await uploadFiles(realClientId);
                if (docPath) {
                    const { error: updateError } = await supabase
                        .from('clients')
                        .update({ core_doc_id: docPath })
                        .eq('id', realClientId);
                    if (updateError) {
                        console.error('[DEBUG] Error updating core_doc_id:', updateError);
                    } else {
                        console.log('[DEBUG] core_doc_id updated:', docPath);
                    }
                }
            }

            // SUCCESS
            alert(editingClient ? 'Client successfully updated!' : 'Client successfully registered!');
            setShowModal(false);
            fetchClients();

        } catch (error) {
            console.error("CRITICAL ERROR SAVING:", error);
            alert("Error: " + (error.message || "Unknown error"));
        } finally {
            console.log("[DEBUG] Finalizing process (finally).");
            setSaving(false);
        }
    };

    return (
        <div style={{ padding: '2rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
                <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#1f2937' }}>Manage Clients</h1>
                <button
                    onClick={handleNew}
                    style={{
                        backgroundColor: '#ea580c',
                        color: 'white',
                        padding: '0.5rem 1rem',
                        borderRadius: '0.25rem',
                        border: 'none',
                        cursor: 'pointer'
                    }}
                >
                    + New Client
                </button>
            </div>

            {loading ? (
                <p>Loading...</p>
            ) : (
                <div style={{ background: 'white', boxShadow: '0 1px 3px 0 rgba(0, 0, 0, 0.1)', borderRadius: '0.5rem', overflow: 'hidden' }}>
                    <table style={{ width: '100%', textAlign: 'left', borderCollapse: 'collapse' }}>
                        <thead style={{ background: '#f9fafb', borderBottom: '1px solid #e5e7eb' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontWeight: '600', color: '#4b5563' }}>Company</th>
                                <th style={{ padding: '1rem', fontWeight: '600', color: '#4b5563' }}>Description</th>
                                <th style={{ padding: '1rem', fontWeight: '600', color: '#4b5563' }}>Tone of Voice</th>
                                <th style={{ padding: '1rem', fontWeight: '600', color: '#4b5563', width: '120px' }}>Connection</th>
                                <th style={{ padding: '1rem', fontWeight: '600', color: '#4b5563', textAlign: 'right' }}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {clients.length === 0 ? (
                                <tr>
                                    <td colSpan="5" style={{ padding: '2rem', textAlign: 'center', color: '#6b7280' }}>
                                        No clients registered.
                                    </td>
                                </tr>
                            ) : (
                                clients.map((client) => (
                                    <tr key={client.id} style={{ borderBottom: '1px solid #e5e7eb' }}>
                                        <td style={{ padding: '1rem', fontWeight: '500' }}>{client.name}</td>
                                        <td style={{ padding: '1rem', color: '#6b7280', fontSize: '0.875rem', maxWidth: '20rem', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                            {client.description}
                                        </td>
                                        <td style={{ padding: '1rem', fontSize: '0.875rem' }}>{client.tone_of_voice}</td>
                                        <td style={{ padding: '1rem' }}>
                                            {client.unipile_account_id ? (
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '4px', color: '#0077b5', fontSize: '0.8rem', fontWeight: '600' }}>
                                                    <Linkedin size={16} /> OK
                                                </div>
                                            ) : (
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '4px', color: '#9ca3af', fontSize: '0.8rem' }} title="Pending Unipile ID">
                                                    <AlertTriangle size={16} /> Pending
                                                </div>
                                            )}
                                        </td>
                                        <td style={{ padding: '1rem', textAlign: 'right' }}>
                                            <button
                                                onClick={() => handleCopyLink(client)}
                                                style={{
                                                    background: 'transparent',
                                                    border: 'none',
                                                    cursor: 'pointer',
                                                    color: '#16a34a', // Green
                                                    padding: '0.25rem',
                                                    marginRight: '0.5rem'
                                                }}
                                                title="Copy Access Link"
                                            >
                                                <LinkIcon size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleEdit(client)}
                                                style={{
                                                    background: 'transparent',
                                                    border: 'none',
                                                    cursor: 'pointer',
                                                    color: '#2563eb',
                                                    padding: '0.25rem'
                                                }}
                                                title="Edit / View Details"
                                            >
                                                <Pencil size={18} />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            )}

            {/* TOAST */}
            {toast && (
                <div style={{
                    position: 'fixed',
                    bottom: '2rem',
                    right: '2rem',
                    background: toast.type === 'error' ? '#ef4444' : '#22c55e',
                    color: 'white',
                    padding: '1rem 1.5rem',
                    borderRadius: '8px',
                    boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '8px',
                    zIndex: 100,
                    animation: 'slideIn 0.3s ease-out'
                }}>
                    <Check size={18} />
                    <span style={{ fontWeight: 600 }}>{toast.message}</span>
                </div>
            )}

            {/* MODAL */}
            {showModal && (
                <div style={{
                    position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
                    background: 'rgba(0,0,0,0.5)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 50
                }}>
                    <div style={{ background: 'white', padding: '2rem', borderRadius: '0.5rem', width: '100%', maxWidth: '500px', maxHeight: '90vh', overflowY: 'auto' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                            <h2 style={{ margin: 0 }}>
                                {editingClient ? 'Edit Client' : 'New Client'}
                            </h2>
                            <button
                                type="button"
                                onClick={() => setShowModal(false)}
                                style={{
                                    background: 'transparent',
                                    border: 'none',
                                    cursor: 'pointer',
                                    color: '#6b7280',
                                    padding: '4px',
                                    borderRadius: '50%',
                                    display: 'flex',
                                    alignItems: 'center',
                                    justifyContent: 'center',
                                    transition: 'background 0.2s'
                                }}
                                onMouseEnter={(e) => e.currentTarget.style.background = '#f3f4f6'}
                                onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                            >
                                <X size={24} />
                            </button>
                        </div>
                        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>

                            {/* Unipile ID Section - Priority */}
                            <div style={{ background: '#eff6ff', border: '1px solid #bfdbfe', borderRadius: '6px', padding: '1rem' }}>
                                <div style={{ display: 'flex', gap: '0.75rem', marginBottom: '0.75rem' }}>
                                    <Info style={{ color: '#2563eb', flexShrink: 0, marginTop: '2px' }} size={20} />
                                    <div>
                                        <h4 style={{ margin: '0 0 0.25rem 0', fontSize: '0.9rem', color: '#1e40af' }}>LinkedIn Integration (Required)</h4>
                                        <p style={{ margin: 0, fontSize: '0.8rem', color: '#1e3a8a', lineHeight: '1.4' }}>
                                            ⚠️ Important: To get this ID, you must first manually connect this client's LinkedIn profile through the Unipile Dashboard. Copy the <strong>'Account ID'</strong> generated there and paste it below.
                                        </p>
                                    </div>
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.85rem', fontWeight: 'bold', color: '#1e3a8a' }}>
                                        Unipile Account ID (LinkedIn)
                                    </label>
                                    <input
                                        name="unipile_account_id"
                                        value={formData.unipile_account_id}
                                        onChange={handleInputChange}
                                        placeholder="Ex: f7NRx9..."
                                        style={{ width: '100%', padding: '0.5rem', border: '1px solid #93c5fd', borderRadius: '4px', fontFamily: 'monospace', color: '#1f2937' }}
                                    />
                                </div>
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Company Name</label>
                                <input
                                    required
                                    name="name"
                                    value={formData.name}
                                    onChange={handleInputChange}
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                />
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Contact Email</label>
                                <input
                                    type="email"
                                    name="email_contato"
                                    value={formData.email_contato}
                                    onChange={handleInputChange}
                                    placeholder="email@empresa.com"
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                />
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Business Description</label>
                                <textarea
                                    required
                                    name="description"
                                    value={formData.description}
                                    onChange={handleInputChange}
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                    rows="3"
                                />
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Tone of Voice</label>
                                <select
                                    name="tone_of_voice"
                                    value={formData.tone_of_voice}
                                    onChange={handleInputChange}
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                >
                                    <option>Professional</option>
                                    <option>Casual</option>
                                    <option>Authoritative</option>
                                    <option>Educational</option>
                                </select>
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Target Audience (Default)</label>
                                <input
                                    name="target_audience_default"
                                    value={formData.target_audience_default}
                                    onChange={handleInputChange}
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                />
                            </div>

                            <div>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem' }}>Pain Points</label>
                                <textarea
                                    name="pain_points"
                                    value={formData.pain_points}
                                    onChange={handleInputChange}
                                    style={{ width: '100%', padding: '0.5rem', border: '1px solid #d1d5db', borderRadius: '0.25rem', color: '#1f2937' }}
                                    rows="3"
                                />
                            </div>

                            {/* DOCUMENT UPLOAD SECTION */}
                            <div style={{ borderTop: '1px solid #e5e7eb', paddingTop: '1rem', marginTop: '0.5rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontSize: '0.875rem', fontWeight: '600' }}>
                                    Context Files (PDF, DOC)
                                </label>

                                <div style={{
                                    border: '1px dashed #d1d5db',
                                    borderRadius: '0.25rem',
                                    padding: '1rem',
                                    textAlign: 'center',
                                    marginBottom: '1rem',
                                    cursor: 'pointer',
                                    position: 'relative'
                                }}>
                                    <input
                                        type="file"
                                        multiple
                                        onChange={handleFileChange}
                                        style={{
                                            position: 'absolute',
                                            top: 0,
                                            left: 0,
                                            width: '100%',
                                            height: '100%',
                                            opacity: 0,
                                            cursor: 'pointer'
                                        }}
                                    />
                                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.5rem', color: '#6b7280' }}>
                                        <Upload size={24} />
                                        <span style={{ fontSize: '0.875rem' }}>Click or drag files here</span>
                                    </div>
                                </div>

                                {/* LISTA DE ARQUIVOS PENDENTES */}
                                {filesToUpload.length > 0 && (
                                    <div style={{ marginBottom: '1rem' }}>
                                        <p style={{ fontSize: '0.75rem', fontWeight: 'bold', color: '#4b5563', marginBottom: '0.25rem' }}>Ready to upload:</p>
                                        <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                                            {filesToUpload.map((file, idx) => (
                                                <li key={idx} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', fontSize: '0.875rem', background: '#f9fafb', padding: '0.25rem 0.5rem', marginBottom: '0.25rem', borderRadius: '0.25rem' }}>
                                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', overflow: 'hidden' }}>
                                                        <FileText size={14} color="#4b5563" />
                                                        <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{file.name}</span>
                                                    </div>
                                                    <button
                                                        type="button"
                                                        onClick={() => removeFileToUpload(idx)}
                                                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#ef4444', padding: 0 }}
                                                    >
                                                        <X size={14} />
                                                    </button>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}

                                {/* LISTA DE ARQUIVOS JÁ EXISTENTES (Storage) */}
                                {existingFiles.length > 0 && (
                                    <div>
                                        <p style={{ fontSize: '0.75rem', fontWeight: 'bold', color: '#4b5563', marginBottom: '0.25rem' }}>Previous Files:</p>
                                        <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
                                            {existingFiles.map((file) => (
                                                <li
                                                    key={file.id || file.name}
                                                    style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', fontSize: '0.875rem', color: '#059669', marginBottom: '0.25rem', background: '#f0fdf4', padding: '0.25rem 0.5rem', borderRadius: '0.25rem' }}
                                                >
                                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', overflow: 'hidden' }}>
                                                        <Check size={14} />
                                                        <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{file.name}</span>
                                                    </div>
                                                    <button
                                                        type="button"
                                                        onClick={() => handleDownloadFile(file.name)}
                                                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#2563eb', padding: '2px', display: 'flex', alignItems: 'center' }}
                                                        title="Download file"
                                                    >
                                                        <Download size={14} />
                                                    </button>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', gap: '0.5rem', marginTop: '1rem' }}>
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    style={{ flex: 1, padding: '0.5rem', background: '#f3f4f6', border: 'none', borderRadius: '0.25rem', cursor: 'pointer' }}
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    disabled={saving}
                                    style={{ flex: 1, padding: '0.5rem', background: '#ea580c', color: 'white', border: 'none', borderRadius: '0.25rem', cursor: 'pointer' }}
                                >
                                    {saving ? 'Saving...' : (editingClient ? 'Save Changes' : 'Save Client')}
                                </button>
                            </div>

                            {editingClient && (
                                <button
                                    type="button"
                                    onClick={handleDelete}
                                    disabled={saving}
                                    style={{ width: '100%', marginTop: '0.5rem', padding: '0.5rem', background: '#fee2e2', color: '#ef4444', border: 'none', borderRadius: '0.25rem', cursor: 'pointer', fontWeight: '500' }}
                                >
                                    Delete Client
                                </button>
                            )}
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react'
import { supabase } from '../services/supabaseClient'
import { useAuth } from '../contexts/AuthContext'
import { useClientSelection } from '../contexts/ClientSelectionContext'
import {
    Library,
    Plus,
    Search,
    BookOpen,
    Video,
    FileText,
    Link as LinkIcon,
    Trash2,
    Edit2,
    X,
    Loader2,
    Magnet
} from 'lucide-react'

// Map content types to icons and colors
const TYPE_CONFIG = {
    'Lead Magnet': { icon: Magnet, color: 'text-purple-500', bg: 'bg-purple-50', border: 'border-purple-200' },
    'Video': { icon: Video, color: 'text-blue-500', bg: 'bg-blue-50', border: 'border-blue-200' },
    'Post': { icon: FileText, color: 'text-orange-500', bg: 'bg-orange-50', border: 'border-orange-200' },
    'Artigo': { icon: BookOpen, color: 'text-emerald-500', bg: 'bg-emerald-50', border: 'border-emerald-200' },
    'Outro': { icon: LinkIcon, color: 'text-gray-500', bg: 'bg-gray-50', border: 'border-gray-200' }
}

const ContentLibraryPage = () => {
    const { user } = useAuth()
    const { selectedClientId } = useClientSelection()
    const [contents, setContents] = useState([])
    const [loading, setLoading] = useState(true)
    const [searchQuery, setSearchQuery] = useState('')

    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false)
    const [editingContent, setEditingContent] = useState(null)
    const [formData, setFormData] = useState({
        content_name: '',
        content_description: '',
        template_text: '',
        content_url: '',
        content_type: 'Lead Magnet'
    })
    const [saving, setSaving] = useState(false)

    useEffect(() => {
        if (user && selectedClientId) {
            fetchContents()
        } else {
            setContents([])
            setLoading(false)
        }
    }, [user, selectedClientId])

    const fetchContents = async () => {
        if (!selectedClientId) return
        try {
            setLoading(true)
            const { data, error } = await supabase
                .from('content_library')
                .select('*')
                .eq('client_id', selectedClientId)
                .order('created_at', { ascending: false })

            if (error) throw error
            setContents(data || [])
        } catch (err) {
            console.error('Error fetching content library:', err)
            // Optionally add toast notifications here
        } finally {
            setLoading(false)
        }
    }

    const handleOpenModal = (content = null) => {
        if (content) {
            setEditingContent(content)
            setFormData({
                content_name: content.content_name,
                content_description: content.content_description || '',
                template_text: content.template_text || '',
                content_url: content.content_url,
                content_type: content.content_type
            })
        } else {
            setEditingContent(null)
            setFormData({
                content_name: '',
                content_description: '',
                template_text: '',
                content_url: '',
                content_type: 'Lead Magnet'
            })
        }
        setIsModalOpen(true)
    }

    const handleCloseModal = () => {
        setIsModalOpen(false)
        setEditingContent(null)
    }

    const handleSave = async (e) => {
        e.preventDefault()
        if (!user) return

        try {
            setSaving(true)

            const payload = {
                ...formData,
                user_id: user.id,
                client_id: selectedClientId
            }

            if (editingContent) {
                const { error } = await supabase
                    .from('content_library')
                    .update(payload)
                    .eq('id', editingContent.id)
                if (error) throw error
            } else {
                const { error } = await supabase
                    .from('content_library')
                    .insert([payload])
                if (error) throw error
            }

            await fetchContents()
            handleCloseModal()
        } catch (err) {
            console.error('Error saving content:', err)
        } finally {
            setSaving(false)
        }
    }

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to remove this content from the library?')) return

        try {
            const { error } = await supabase
                .from('content_library')
                .delete()
                .eq('id', id)

            if (error) throw error
            setContents(prev => prev.filter(c => c.id !== id))
        } catch (err) {
            console.error('Error deleting content:', err)
        }
    }

    // Filter contents based on search query
    const filteredContents = contents.filter(c =>
        c.content_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (c.content_description && c.content_description.toLowerCase().includes(searchQuery.toLowerCase()))
    )

    return (
        <div className="min-h-screen bg-gray-50 text-gray-900 p-4 sm:p-6 lg:p-8">
            <div className="max-w-7xl mx-auto space-y-6">

                {/* Header */}
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div className="flex items-center gap-3">
                        <div className="w-12 h-12 rounded-2xl bg-orange-50 flex items-center justify-center border border-orange-200/50">
                            <Library className="text-orange-500" size={24} />
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold tracking-tight text-gray-900">Content Library</h1>
                            <p className="text-sm text-gray-500">Manage links, materials, and templates for approaches.</p>
                        </div>
                    </div>
                    <button
                        onClick={() => handleOpenModal()}
                        className="flex items-center gap-2 px-5 py-2.5 bg-gray-900 text-white font-medium rounded-xl hover:bg-gray-800 transition-all shadow-sm shrink-0"
                    >
                        <Plus size={18} />
                        Add Material
                    </button>
                </div>

                {/* No client selected guard */}
                {!selectedClientId ? (
                    <div className="bg-white border text-center border-gray-200 rounded-3xl p-12">
                        <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-gray-100">
                            <Library className="text-gray-400" size={28} />
                        </div>
                        <h3 className="text-gray-900 font-bold text-lg mb-2">Select a client</h3>
                        <p className="text-sm text-gray-500 max-w-sm mx-auto">
                            Select a client from the selector above to view and manage the content library.
                        </p>
                    </div>
                ) : (
                    <>

                        {/* Toolbar */}
                        <div className="bg-white p-4 rounded-2xl border border-gray-200">
                            <div className="relative max-w-md">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    placeholder="Search content by name or context..."
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    className="w-full pl-10 pr-4 py-2 border border-gray-200 font-medium rounded-xl text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500"
                                />
                            </div>
                        </div>

                        {/* Content Grid */}
                        {loading ? (
                            <div className="flex items-center justify-center py-20">
                                <Loader2 className="animate-spin text-orange-500" size={32} />
                            </div>
                        ) : filteredContents.length === 0 ? (
                            <div className="bg-white border text-center border-gray-200 rounded-3xl p-12 dashed-border">
                                <div className="w-16 h-16 bg-gray-50 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-gray-100">
                                    <Library className="text-gray-400" size={28} />
                                </div>
                                <h3 className="text-gray-900 font-bold text-lg mb-2">Empty library</h3>
                                <p className="text-sm text-gray-500 mb-6 max-w-sm mx-auto">
                                    {searchQuery ? 'Your search returned no results.' : 'There are no materials in your sales library yet. Add links, PDFs, posts, or videos.'}
                                </p>
                                {!searchQuery && (
                                    <button
                                        onClick={() => handleOpenModal()}
                                        className="px-6 py-2 bg-orange-50 text-orange-600 font-semibold rounded-full hover:bg-orange-100 transition-colors inline-flex items-center gap-2"
                                    >
                                        <Plus size={18} />
                                        Create first content
                                    </button>
                                )}
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                                {filteredContents.map(item => {
                                    const typeConf = TYPE_CONFIG[item.content_type] || TYPE_CONFIG['Outro']
                                    const TypeIcon = typeConf.icon

                                    return (
                                        <div key={item.id} className="bg-white rounded-2xl border border-gray-200 p-5 hover:shadow-lg hover:border-gray-300 transition-all group flex flex-col h-full">
                                            <div className="flex items-start justify-between mb-4">
                                                <div className={`p-2.5 rounded-xl border ${typeConf.bg} ${typeConf.border} ${typeConf.color}`}>
                                                    <TypeIcon size={20} />
                                                </div>
                                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={() => handleOpenModal(item)}
                                                        className="p-1.5 text-gray-400 hover:text-gray-700 hover:bg-gray-100 rounded-lg transition-colors"
                                                    >
                                                        <Edit2 size={15} />
                                                    </button>
                                                    <button
                                                        onClick={() => handleDelete(item.id)}
                                                        className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                                    >
                                                        <Trash2 size={15} />
                                                    </button>
                                                </div>
                                            </div>

                                            <div className="flex-1 mb-4">
                                                <h3 className="font-bold text-gray-900 mb-1 line-clamp-2">{item.content_name}</h3>
                                                {item.content_description && (
                                                    <p className="text-xs text-gray-500 line-clamp-3 leading-relaxed">
                                                        {item.content_description}
                                                    </p>
                                                )}
                                            </div>

                                            <div className="pt-4 border-t border-gray-100 flex items-center justify-between mt-auto">
                                                <span className="text-[10px] font-bold tracking-wider text-gray-400 uppercase bg-gray-50 px-2 py-1 rounded-md">
                                                    {item.content_type}
                                                </span>
                                                <a
                                                    href={item.content_url}
                                                    target="_blank"
                                                    rel="noreferrer"
                                                    className="text-xs font-semibold text-orange-500 hover:text-orange-600 flex items-center gap-1 hover:underline"
                                                >
                                                    Open link <LinkIcon size={12} />
                                                </a>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        )}
                    </>
                )}
            </div>

            {/* Modal de Criar/Editar */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-gray-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-3xl w-full max-w-lg shadow-2xl border border-gray-200 overflow-hidden" style={{ animation: 'slideUp 0.3s cubic-bezier(0.16, 1, 0.3, 1)' }}>
                        <div className="px-6 py-4 flex items-center justify-between border-b border-gray-100 bg-gray-50/50">
                            <h2 className="text-lg font-bold text-gray-900">
                                {editingContent ? 'Edit Material' : 'Add to Library'}
                            </h2>
                            <button onClick={handleCloseModal} className="text-gray-400 hover:text-gray-600 bg-white p-2 rounded-xl border border-gray-200 shadow-sm">
                                <X size={18} />
                            </button>
                        </div>

                        <form onSubmit={handleSave} className="p-6 space-y-5">
                            <div>
                                <label className="block text-xs font-bold text-gray-700 uppercase tracking-widest mb-1">Title/Name</label>
                                <input
                                    required
                                    type="text"
                                    value={formData.content_name}
                                    onChange={e => setFormData({ ...formData, content_name: e.target.value })}
                                    placeholder="Ex: Demo Video V2"
                                    className="w-full px-4 py-2.5 font-medium border border-gray-200 rounded-xl text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all"
                                />
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-gray-700 uppercase tracking-widest mb-1">Usage Context</label>
                                <textarea
                                    value={formData.content_description}
                                    onChange={e => setFormData({ ...formData, content_description: e.target.value })}
                                    placeholder="Ex: Use this video if the lead asks about competitors..."
                                    rows={2}
                                    className="w-full px-4 py-2.5 font-medium border border-gray-200 rounded-xl text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all resize-none"
                                />
                            </div>

                            <div>
                                <label className="block text-xs font-bold text-gray-700 uppercase tracking-widest mb-1">Chat Template Text (Quick Actions)</label>
                                <textarea
                                    value={formData.template_text}
                                    onChange={e => setFormData({ ...formData, template_text: e.target.value })}
                                    placeholder="Ex: Hi {{first_name}}, I thought you might find this interesting: "
                                    rows={2}
                                    className="w-full px-4 py-2.5 font-medium border border-gray-200 rounded-xl text-sm text-gray-900 focus:outline-none focus:ring-2 focus:ring-purple-500/20 focus:border-purple-500 transition-all resize-none bg-purple-50/30"
