    // 4. Action Handlers
    const handleOpenChat = (authorUrnId) => {
        console.log('handleOpenChat:', authorUrnId)
    }

    const handleConnect = (authorUrnId, noteText) => {
        console.log('handleConnect:', authorUrnId, noteText)
        setConnectModal(null)
        setConnectNote('')
