                    </button>
                </div>
                <p style={{ color: '#6B7280', fontSize: '0.875rem', margin: 0, paddingLeft: '1.25rem' }}>
                    Your real performance metrics — filter by profile for a detailed view.
                </p>
            </div>

            {/* Error Banner */}
            {error && (
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.75rem 1rem', background: '#FEF2F2', border: '1px solid #FECACA', borderLeft: '4px solid #EF4444', marginBottom: '1.5rem', fontSize: '0.8rem', color: '#991B1B' }}>
                    <AlertTriangle size={14} />
                    {error}
                </div>
            )}

            {/* Profile Filter Bar */}
            <div style={{ background: '#F9FAFB', border: '1px solid #E5E7EB', padding: '0.75rem 1rem', marginBottom: '2rem', display: 'flex', alignItems: 'center', gap: '0.5rem', flexWrap: 'wrap' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.35rem', marginRight: '0.5rem', color: '#9CA3AF' }}>
                    <Layers size={13} />
                    <span style={{ fontSize: '0.62rem', fontWeight: '700', letterSpacing: '0.08em', textTransform: 'uppercase', color: '#9CA3AF' }}>Filters</span>
                </div>
                <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', alignItems: 'flex-end' }}>
                    <StyledSelect
                        label="My Professional Profile"
                        value={selectedProfile}
                        onChange={setSelectedProfile}
                        options={loadingProfiles ? [] : [{ id: 'all', name: 'Overview (All Profiles)' }, ...clientProfiles]}
                        placeholder={loadingProfiles ? "Loading profiles..." : ""}
                        disabled={loadingProfiles}
                    />

                    <div style={{ width: '1px', background: '#E5E7EB', height: '38px', alignSelf: 'flex-end', marginBottom: '2px' }} />

                    <StyledSelect
                        label="Date Range"
                        value={dateRange}
                        onChange={setDateRange}
                        options={[
                            { id: 'all', name: 'All Time' },
                            { id: '7d', name: 'Last 7 days' },
                            { id: '15d', name: 'Last 15 days' },
                            { id: '30d', name: 'Last 30 days' }
                        ]}
                        placeholder="Loading..."
                        disabled={loadingProfiles}
                    />
                </div>

                {loading && (
                    <div style={{ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '0.35rem', color: '#9CA3AF', fontSize: '0.7rem' }}>
                        <Loader2 size={12} style={{ animation: 'spin 1s linear infinite' }} />
                        Loading...
                    </div>
                )}
            </div>

            {/* KPI Grid */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                gap: '1px',
                background: '#E5E7EB',
                border: '1px solid #E5E7EB',
                marginBottom: '2rem',
            }}>
                {KPI_DEFS.map((kpi, i) => (
                    <KpiCard
                        key={`${kpi.id}-${selectedProfile}`}
                        kpi={kpi}
                        value={stats[kpi.id]}
                        index={i}
                        loading={loading}
                    />
                ))}
            </div>

            {/* Chart Section */}
            <div style={{ background: '#fff', border: '1px solid #E5E7EB', padding: '1.5rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '1.25rem' }}>
                    <div style={{ width: '4px', height: '16px', background: '#F97316' }} />
                    <h2 style={{ fontSize: '0.8rem', fontWeight: '800', color: '#374151', margin: 0, textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                        Prospections — Last 7 days
                    </h2>
                </div>

                {loading ? (
                    <div style={{ height: '220px', background: '#F9FAFB', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#9CA3AF', fontSize: '0.8rem', gap: '0.5rem' }}>
                        <Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> Loading chart...
                    </div>
                ) : (
                    <ResponsiveContainer width="100%" height={220}>
                        <BarChart data={chartData} barCategoryGap="35%">
                            <CartesianGrid vertical={false} stroke="#F3F4F6" />
                            <XAxis
                                dataKey="day"
                                tick={{ fontSize: 11, fill: '#9CA3AF', fontWeight: 600 }}
                                axisLine={false}
                                tickLine={false}
                            />
                            <YAxis
                                allowDecimals={false}
                                tick={{ fontSize: 11, fill: '#9CA3AF' }}
                                axisLine={false}
                                tickLine={false}
                                width={32}
                            />
                            <Tooltip content={<CustomTooltip />} cursor={{ fill: '#F97316', opacity: 0.06 }} />
                            <Bar
                                dataKey="Prospections"
                                fill="#F97316"
                                radius={[2, 2, 0, 0]}
                                maxBarSize={48}
                            />
                        </BarChart>
                    </ResponsiveContainer>
                )}
            </div>

            {/* spin keyframe (also used by RefreshCw / Loader2) */}
            <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
    )
}

export default MyAnalyticsPage

import React, { useState, useEffect, useRef } from 'react'
import { supabase } from '../services/supabaseClient'
import { useClientSelection } from '../contexts/ClientSelectionContext'
import { useParams, useNavigate } from 'react-router-dom'
import {
    Search,
    Loader2,
    Sparkles,
    Briefcase,
    Gem,
    Building2,
    Globe,
    Send,
    Bot,
    Plus,
    Check,
    Zap,
    RefreshCw,
    X,
    Trash2,
    MapPin,
    Copy,
    ExternalLink,
    ArrowUpDown,
    Filter,
    ChevronsUpDown,
    ArrowLeft,
    Users,
    MessageSquare,
    History,
    Clock,
    ChevronLeft,
    ChevronRight,
    MessageCircle,
    Trophy,
    Medal,
    Brain
} from 'lucide-react'
import AddLeadsModal from '../components/AddLeadsModal'
import LeadDetailModal from '../components/LeadDetailModal'
import HistorySyncModal from '../components/HistorySyncModal'
import LeadAvatar from '../components/LeadAvatar'

const NetworkDashboard = () => {
    const { id: campaignId } = useParams()
    const navigate = useNavigate()
    const { selectedClientId } = useClientSelection()

    const [campaign, setCampaign] = useState(null)
    const [clientName, setClientName] = useState('')
    const [leads, setLeads] = useState([]) // Stores the JOINED object: { ...campaign_lead, leads: { ...lead_data } }
    const [loading, setLoading] = useState(false)
    const [selectedLead, setSelectedLead] = useState(null) // This will store the full enriched object for the drawer
    const [searchTerm, setSearchTerm] = useState('')
    const [debouncedSearch, setDebouncedSearch] = useState('')
    const [stats, setStats] = useState({ total: 0, hot: 0, interactions: 0 })
    const [totalMessages, setTotalMessages] = useState(0)
    const [topLeads, setTopLeads] = useState([])

    // Chat/Interactions State
    const [interactions, setInteractions] = useState([])
    const [loadingChat, setLoadingChat] = useState(false)

    // Data Table State
    const [selectedLeads, setSelectedLeads] = useState(new Set())
    const [sortConfig, setSortConfig] = useState({ key: 'created_at', direction: 'desc' })
    const [filters, setFilters] = useState({
        status: [],
        qualification: [],
        company: '',
        role: '',
        hasMessages: '' // 'yes', 'no', or ''
    })
    const [isFilterOpen, setIsFilterOpen] = useState(false)

    // Pagination State
    const [page, setPage] = useState(0)
    const [hasMore, setHasMore] = useState(true)
    const [loadingMore, setLoadingMore] = useState(false)
    const ITEMS_per_PAGE = 50

    // Logic State
    const [enrichmentLoading, setEnrichmentLoading] = useState(false)
    const [notification, setNotification] = useState(null)
    const [sendingMessage, setSendingMessage] = useState(false)
    const [icebreakerLoading, setIcebreakerLoading] = useState(null) // ID of lead being processed
    const [messageDraft, setMessageDraft] = useState('')
    const [isAddLeadsModalOpen, setIsAddLeadsModalOpen] = useState(false)
    const [syncLoading, setSyncLoading] = useState(false)
    const [emergencySyncLoading, setEmergencySyncLoading] = useState(false)
    const [clientSyncTimestamp, setClientSyncTimestamp] = useState(null) // from clients.last_sync_timestamp

    // Bulk History Import State (legacy queue kept for backward compat)
    const [importQueue, setImportQueue] = useState({
        active: false,
        current: 0,
        total: 0,
        failures: 0,
        currentLeadName: ''
    })
    const [showImportConfirm, setShowImportConfirm] = useState(false)

    // ARQUEÓLOGO: Sequential orchestration state
    const [showHistorySyncModal, setShowHistorySyncModal] = useState(false)
    const [syncProgress, setSyncProgress] = useState({ status: 'idle', current: 0, total: 0, failures: 0 })
    const cancelRef = useRef(false)



    // Helper function for delay (Safe Queue Pattern)
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms))



    // Debounce Search
    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedSearch(searchTerm)
        }, 500)
        return () => clearTimeout(timer)
    }, [searchTerm])

    useEffect(() => {
        if (selectedLead) {
            setMessageDraft(selectedLead.suggested_message || '')
        }

        // Fetch Interactions (Chat History)
        if (!selectedLead?.id) {
            setInteractions([])
            return // Don't fetch if no lead
        }

        const fetchInteractions = async () => {
            setLoadingChat(true)
            try {
                const { data, error } = await supabase
                    .from('interactions')
                    .select('*')
                    .eq('lead_id', selectedLead.id)
                    .order('interaction_date', { ascending: false })

                if (error) throw error
                setInteractions(data || [])
            } catch (err) {
                console.error('Erro ao buscar interações:', err)
            } finally {
                setLoadingChat(false)
            }
        }

        fetchInteractions()
    }, [selectedLead])



    // Realtime Subscription
    useEffect(() => {
        if (!selectedClientId) return

        const channel = supabase
            .channel(`campaign_leads_changes_client_${selectedClientId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'campaign_leads',
                    filter: `client_id=eq.${selectedClientId}`
                },
                (payload) => {
                    // Refresh data on any change
                    console.log('Realtime update:', payload)
                    fetchLeads(0, true)
                    fetchStats()
                }
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [selectedClientId])


    const fetchClientDetails = async () => {
        if (!selectedClientId) return
        const { data } = await supabase
            .from('clients')
            .select('nome')
            .eq('id', selectedClientId)
            .single()
        if (data) setClientName(data.nome)
    }

    const fetchClientSyncTimestamp = async () => {
        if (!selectedClientId) return
        try {
            const { data } = await supabase
                .from('clients')
                .select('last_sync_timestamp')
                .eq('id', selectedClientId)
                .single()

            if (data?.last_sync_timestamp) {
                setClientSyncTimestamp(data.last_sync_timestamp)
            }
        } catch (err) {
            console.error('Error fetching client sync timestamp:', err)
        }
    }

    const fetchStats = async () => {
        if (!selectedClientId) return

        try {
            const { count: totalCount } = await supabase
                .from('campaign_leads')
                .select('*', { count: 'exact', head: true })
                .eq('client_id', selectedClientId) // Multi-tenant guard

            setStats(prev => ({ ...prev, total: totalCount || 0 }))

        } catch (error) {
            console.error('Erro ao buscar KPIs:', error)
        }
    }

    // Fetch Total Messages (Filtered by Client only)
    const fetchTotalMessages = async () => {
        if (!selectedClientId) return
        try {
            const { count, error } = await supabase
                .from('interactions')
                .select('*', { count: 'exact', head: true })
                .eq('client_id', selectedClientId)

            if (error) throw error
            setTotalMessages(count || 0)
        } catch (err) {
            console.error('Erro ao buscar total de mensagens:', err)
        }
    }

    // Fetch Top Leads (Engagement Ranking — Filtered by Client)
    const fetchTopLeads = async () => {
        if (!selectedClientId) return
        try {
            const { data, error } = await supabase
                .from('leads')
                .select('id, nome, avatar_url, total_interactions_count, empresa')
                .eq('client_id', selectedClientId)
                .gt('total_interactions_count', 0)
                .order('total_interactions_count', { ascending: false })
                .limit(5)

            if (error) throw error
            setTopLeads(data || [])
        } catch (err) {
            console.error('Erro ao buscar top leads:', err)
        }
    }

    // SIMPLIFIED FETCH: Query leads directly
    const fetchLeads = async (pageIndex = 0, isRefresh = false) => {
        if (!selectedClientId) return

        try {
            if (pageIndex === 0) setLoading(true)
            else setLoadingMore(true)

            const from = pageIndex * ITEMS_per_PAGE
            const to = from + ITEMS_per_PAGE - 1

            // Multi-tenant isolation: client_id directly on leads
            let query = supabase
                .from('leads')
                .select('*', { count: 'exact' })
                .eq('client_id', selectedClientId)
                .neq('is_blacklisted', true)
                .range(from, to)

            // Direct sorting
            if (sortConfig.key) {
                query = query.order(sortConfig.key, { ascending: sortConfig.direction === 'asc' })
            } else {
                query = query.order('created_at', { ascending: false })
            }

            // Direct search
            if (debouncedSearch) {
                query = query.or(`nome.ilike.%${debouncedSearch}%,empresa.ilike.%${debouncedSearch}%,headline.ilike.%${debouncedSearch}%`)
            }

            // Direct filters
            // if (filters.status.length > 0) {
            //     query = query.in('status_pipeline', filters.status)
            // }

            if (filters.qualification.length > 0) {
                query = query.in('icp_score', filters.qualification)
            }

            if (filters.hasMessages === 'yes') {
                query = query.gt('total_interactions_count', 0)
            } else if (filters.hasMessages === 'no') {
                query = query.eq('total_interactions_count', 0)
            }

            const { data, error, count } = await query

            console.log('[Fetch Results] Data:', data)
            console.log('[Fetch Results] Count:', count)
            console.log('[Fetch Results] Error:', error)

            if (error) throw error

            if (data) {
                console.log(`[Fetch Success] Retrieved ${data.length} leads`)
                setLeads(data) // Pagination: always replace
                setHasMore(data.length === ITEMS_per_PAGE)
            }
        } catch (err) {
            console.error('Erro ao buscar leads:', err)
        } finally {
            setLoading(false)
            setLoadingMore(false)
        }
    }

    useEffect(() => {
        if (selectedClientId) {
            // Only fetch details once
            if (page === 0) {
                fetchClientDetails()
                fetchClientSyncTimestamp()
            }
        }
    }, [selectedClientId])

    useEffect(() => {
        if (selectedClientId) {
            setLeads([])
            setPage(0)
            setHasMore(true)
            fetchLeads(0, true)
            fetchStats()
        }
    }, [selectedClientId, debouncedSearch, sortConfig, filters])

    // Fetch total messages and top leads when client changes
    useEffect(() => {
        if (selectedClientId) {
            fetchTotalMessages()
            fetchTopLeads()
        } else {
            setTotalMessages(0)
            setTopLeads([])
        }
    }, [selectedClientId])

    // Reset cancel flag on unmount
    useEffect(() => {
        return () => { cancelRef.current = false }
    }, [])

    // --- HANDLERS ---
    const handleSort = (key) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
        }))
    }

    const toggleSelectAll = () => {
        if (selectedLeads.size === leads.length && leads.length > 0) {
            setSelectedLeads(new Set())
        } else {
            setSelectedLeads(new Set(leads.map(l => l.id)))
        }
    }

    const toggleSelectRow = (id, e) => {
        e.stopPropagation()
        const newSet = new Set(selectedLeads)
        if (newSet.has(id)) newSet.delete(id)
        else newSet.add(id)
        setSelectedLeads(newSet)
    }

    const toggleFilterStatus = (statusValue) => {
        setFilters(prev => {
            const current = prev.status
            const newStatus = current.includes(statusValue)
                ? current.filter(s => s !== statusValue)
                : [...current, statusValue]
            return { ...prev, status: newStatus }
        })
    }



    const handleCopy = (text) => {
        navigator.clipboard.writeText(text)
        setNotification({ message: 'Copied to clipboard', type: 'info' })
        setTimeout(() => setNotification(null), 2000)
    }

    const handleSendMessage = async () => {
        if (!selectedLead) return
        setSendingMessage(true)

        try {
            await new Promise(resolve => setTimeout(resolve, 1500))
            setNotification({ message: 'Connection sent successfully!', type: 'success' })
            setSelectedLead(null)
        } catch (e) {
            setNotification({ message: 'Error sending.', type: 'error' })
        } finally {
            setSendingMessage(false)
            setTimeout(() => setNotification(null), 3000)
        }
    }

    // UPDATED: Start Connections Sync (Queue Workflow A)
    const handleEnrichmentQueue = async () => {
        if (!selectedClientId) return
        setEnrichmentLoading(true)
        setNotification({ message: 'Starting background collection...', type: 'info' })

        try {
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/start-connections-sync', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    client_id: selectedClientId
                })
            })

            if (response.ok) {
                setNotification({ message: 'Collection started! Leads will be processed shortly.', type: 'success' })
            } else {
                throw new Error('Webhook failed')
            }

        } catch (error) {
            console.error(error)
            setNotification({ message: 'Error starting enrichment queue.', type: 'error' })
        } finally {
            setEnrichmentLoading(false)
            setTimeout(() => setNotification(null), 5000)
        }
    }

    const handleEmergencySync = async () => {
        if (!selectedClientId) return
        setEmergencySyncLoading(true)

        try {
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/emergency-sync', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    client_id: selectedClientId
                })
            })

            if (response.ok) {
                setNotification({
                    message: "Sincronização iniciada! As novas conexões aparecerão aqui em instantes.",
                    type: 'success'
                })
            } else {
                throw new Error('Webhook failed')
            }

        } catch (error) {
            console.error('Emergency sync error:', error)
            setNotification({
                message: "Erro ao iniciar sincronização de emergência.",
                type: 'error'
            })
        } finally {
            setEmergencySyncLoading(false)
            setTimeout(() => setNotification(null), 5000)
        }
    }

    const handleSyncConnections = async () => {
        if (!selectedClientId) return

        setSyncLoading(true)

        try {
            // 1. Fetch Client Unipile ID
            const { data: client, error } = await supabase
                .from('clients')
                .select('unipile_account_id')
                .eq('id', selectedClientId)
                .single()

            if (error || !client?.unipile_account_id) {
                setNotification({ message: 'Error: Client missing connected Unipile account.', type: 'error' })
                setSyncLoading(false)
                setTimeout(() => setNotification(null), 5000)
                return
            }

            // 2. Call Webhook (Early Return pattern)
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/sync-connections', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    client_id: selectedClientId,
                    unipile_account_id: client.unipile_account_id
                })
            })

            if (response.ok) {
                const result = await response.json()

                // Build rich notification message
                let msg
                if (result.total_leads && result.total_leads > 0) {
                    msg = `We started reading ${result.total_leads.toLocaleString()} connections. The process will take about ${result.estimated_time_human || 'a few minutes'}. You can continue using the system normally.`
                } else {
                    msg = result.message || 'Sync started. The update will appear shortly.'
                }

                setNotification({ message: msg, type: 'success' })
            } else {
                throw new Error(`API failure (${response.status})`)
            }
        } catch (e) {
            console.error(e)
            setNotification({ message: 'Error starting sync.', type: 'error' })
        } finally {
            setSyncLoading(false)
            setTimeout(() => setNotification(null), 10000)
        }
    }

    // NEW: Sync Messages Manual Trigger
    const handleSyncMessages = async () => {
        if (!selectedClientId) return

        setSyncLoading(true)
        setNotification({ message: 'Starting messages sync...', type: 'info' })

        try {
            // 1. Fetch Client Unipile ID & Current User
            const { data: { user } } = await supabase.auth.getUser()

            const { data: client, error } = await supabase
                .from('clients')
                .select('unipile_account_id')
                .eq('id', selectedClientId)
                .single()

            if (error || !client?.unipile_account_id) {
                setNotification({ message: 'Error: Client missing connected Unipile account.', type: 'error' })
                setSyncLoading(false)
                setTimeout(() => setNotification(null), 5000)
                return
            }

            // 2. Call Webhook with Enriched Payload
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/sync-messages', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    account_id: client.unipile_account_id,
                    user_id: user?.id || 'system_user',
                    client_id: selectedClientId
                })
            })

            if (response.ok) {
                // Parse JSON response
                const result = await response.json()

                if (result.success) {
                    const messageCount = result.data?.messages_synced || 0
                    const timestamp = result.data?.last_sync_timestamp || new Date().toISOString()

                    // Update local timestamp (backend saves to DB)
                    setClientSyncTimestamp(timestamp)

                    // Show success with message count
                    setNotification({
                        message: `Sync completed! ${messageCount} messages processed.`,
                        type: 'success'
                    })

                    // Refresh data
                    fetchLeads(0, true)
                    fetchTotalMessages()
                } else {
                    throw new Error(result.message || 'Sync failed')
                }
            } else {
                throw new Error('Error syncing. Try again.')
            }
        } catch (error) {
            console.error(error)
            setNotification({
                message: error.message || 'Error syncing. Try again.',
                type: 'error'
            })
        } finally {
            setSyncLoading(false)
            setTimeout(() => setNotification(null), 5000)
        }
    }

    // NEW: Generate Icebreaker (Workflow D)
    const handleGenerateIcebreaker = async (leadId, e) => {
        e.stopPropagation() // Prevent row click
        if (!selectedClientId || !leadId) return

        setIcebreakerLoading(leadId)
        setNotification({ message: 'Generating personalized Icebreaker...', type: 'info' })

        try {
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/generate-icebreaker', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    lead_id: leadId,
                    client_id: selectedClientId
                })
            })

            if (response.ok) {
                setNotification({ message: 'Icebreaker generated successfully!', type: 'success' })
                // Realtime should update the UI
            } else {
                setNotification({ message: 'Error generating Icebreaker.', type: 'error' })
            }

        } catch (error) {
            console.error(error)
            setNotification({ message: 'Connection error.', type: 'error' })
        } finally {
            setIcebreakerLoading(null)
            setTimeout(() => setNotification(null), 3000)
        }

    }

    const handleDeleteLead = async (id, e) => {
        e.stopPropagation()
        if (!confirm('Are you sure you want to remove this lead from the database?')) return

        try {
            const { error } = await supabase
                .from('campaign_leads')
                .delete()
                .eq('id', id)
                .eq('client_id', selectedClientId) // Multi-tenant guard

            if (error) throw error

            setLeads(prev => prev.filter(l => l.id !== id))
            setStats(prev => ({ ...prev, total: prev.total - 1 }))
            setNotification({ message: 'Lead removed successfully.', type: 'success' })
        } catch (error) {
            console.error('Error deleting lead:', error)
            setNotification({ message: 'Error removing lead.', type: 'error' })
