    // NEW: Manual Sync History (Workflow B - Manual Trigger from Table)
    const handleSyncHistory = async (lead, e) => {
        e.stopPropagation()
        if (!selectedClientId || !lead) return

        if (!confirm('Warning: This action will perform a deep scan of the conversation history from the last year.\\n\\nThis might take a few minutes. Do you wish to continue?')) return

        setNotification({ message: 'Starting complete history import...', type: 'info' })

        try {
            // 1. Fetch Client Unipile Account ID (REQUIRED by webhook)
            const { data: client, error } = await supabase
                .from('clients')
                .select('unipile_account_id')
                .eq('id', selectedClientId)
                .single()

            if (error || !client?.unipile_account_id) {
                setNotification({
                    message: "Connect a LinkedIn account in this client's settings.",
                    type: 'error'
                })
                return
            }

            console.log(`[Sync History] Sending request for lead_id: ${lead.id}, account_id: ${client.unipile_account_id}`)

            // 2. Call Webhook with REQUIRED account_id
            const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/import-history', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    lead_id: lead.id,               // ID REAL do lead (da view leads_with_stats)
                    account_id: client.unipile_account_id
                })
            })

            if (response.ok) {
                setNotification({ message: 'Import started! The process will run in the background.', type: 'success' })
            } else {
                const errorText = await response.text()
                console.error(`Webhook Error: ${response.status}`, errorText)
                setNotification({ message: `Error starting import: ${response.status}`, type: 'error' })
            }
        } catch (e) {
            console.error('Error importing history:', e)
            setNotification({ message: 'Connection error.', type: 'error' })
        }
    }

    // ----------------------------------------------------------------
    // ARQUEÓLOGO: Sequential lead-by-lead webhook orchestration
    // ----------------------------------------------------------------
    const handleBulkHistorySync = async () => {
        if (!selectedClientId || syncProgress.status === 'running') return
        cancelRef.current = false

        try {
            // 1. Fetch exact total pendings bypass 1000 limit
            const { count: totalPendingCount, error: countError } = await supabase
                .from('leads')
                .select('*', { count: 'exact', head: true })
                .eq('client_id', selectedClientId)
                .is('last_history_sync_at', null)

            if (countError) throw countError

            if (totalPendingCount === 0 || totalPendingCount === null) {
                setNotification({ message: 'No sync-pending leads found.', type: 'info' })
                setTimeout(() => setNotification(null), 5000)
                return
            }

            // 2. Paginated Fetching to collect all pending leads
            let allLeads = []
            let fromLimit = 0
            const step = 900

            while (true) {
                const { data: pageData, error: pageError } = await supabase
                    .from('leads')
                    .select('id, nome')
                    .eq('client_id', selectedClientId)
                    .is('last_history_sync_at', null)
                    .range(fromLimit, fromLimit + step - 1)

                if (pageError) throw pageError
                if (!pageData || pageData.length === 0) break

                allLeads.push(...pageData)
                if (pageData.length < step) break

                fromLimit += step
            }

            // 3. Fetch Unipile account ID
            const { data: client, error: clientError } = await supabase
                .from('clients')
                .select('unipile_account_id')
                .eq('id', selectedClientId)
                .single()

            if (clientError || !client?.unipile_account_id) {
                setNotification({ message: "Connect a LinkedIn account in this client\'s settings.", type: 'error' })
                setTimeout(() => setNotification(null), 5000)
                return
            }

            const totalLeads = totalPendingCount
            const accountId = client.unipile_account_id

            // 4. Open modal + set initial progress
            setSyncProgress({ status: 'running', current: 0, total: totalLeads, failures: 0 })
            setShowHistorySyncModal(true)

            let currentFailures = 0
            let currentProcessed = 0

            // 5. Ensure status starts as 'running' and total_leads is accurate in DB
            await supabase
                .from('history_sync_progress')
                .upsert([{
                    client_id: selectedClientId,
                    status: 'running',
                    total_leads: totalLeads,
                    processed: 0,
                    failures: 0,
                    started_at: new Date().toISOString(),
                    completed_at: null,
                    updated_at: new Date().toISOString()
                }], { onConflict: 'client_id' })

            for (let i = 0; i < totalLeads; i++) {
                // Check for cancellation
                if (cancelRef.current) {
                    setSyncProgress(prev => ({ ...prev, status: 'cancelled' }))
                    await supabase
                        .from('history_sync_progress')
                        .update({ status: 'cancelled', processed: currentProcessed, failures: currentFailures, updated_at: new Date().toISOString() })
                        .eq('client_id', selectedClientId)
                    return
                }

                const lead = allLeads[i]
                setSyncProgress(prev => ({ ...prev, current: i + 1 }))

                try {
                    const controller = new AbortController()
                    // 15 seconds timeout to allow n8n to process
                    const timeout = setTimeout(() => controller.abort(), 15000)

                    const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/import-history', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ lead_id: lead.id, account_id: accountId }),
                        signal: controller.signal
                    })

                    clearTimeout(timeout)

                    if (response.ok) {
                        currentProcessed++
                        // Update progress: processed + 1
                        await supabase
                            .from('history_sync_progress')
                            .update({
                                processed: currentProcessed,
                                last_lead_name: lead.nome || 'Unknown',
                                updated_at: new Date().toISOString()
                            })
                            .eq('client_id', selectedClientId)
                    } else {
                        throw new Error(`HTTP Error: ${response.status}`)
                    }

                } catch (err) {
                    // Network error, timeout, or HTTP error — log and increment failures
                    console.warn(`[Arqueólogo] Lead ${lead.id} falhou:`, err.message)
                    currentFailures++
                    setSyncProgress(prev => ({ ...prev, failures: currentFailures }))

                    // Update progress: failures + 1
                    await supabase
                        .from('history_sync_progress')
                        .update({
                            failures: currentFailures,
                            last_lead_name: lead.nome || 'Unknown',
                            updated_at: new Date().toISOString()
                        })
                        .eq('client_id', selectedClientId)
                }

                // 2-second delay between calls (skip on last iteration)
                if (i < totalLeads - 1) {
                    await new Promise(resolve => setTimeout(resolve, 2000))
                }
            }

            // 6. Completed
            setSyncProgress(prev => ({ ...prev, status: 'completed' }))
            await supabase
                .from('history_sync_progress')
                .update({
                    status: 'completed',
                    processed: currentProcessed,
                    failures: currentFailures,
                    completed_at: new Date().toISOString(),
                    updated_at: new Date().toISOString()
                })
                .eq('client_id', selectedClientId)

        } catch (err) {
            console.error('[Arqueólogo] Error:', err)
            setSyncProgress(prev => ({ ...prev, status: 'error' }))
            setNotification({ message: 'Error starting import. Try again.', type: 'error' })
            setTimeout(() => setNotification(null), 5000)
        }
    }

    const handleCancelSync = async () => {
        cancelRef.current = true
    }

    const cancelImport = () => {
        setShowImportConfirm(false)
    }

    const executeHistoryImport = async () => {
        setShowImportConfirm(false)
        if (!selectedClientId || !campaignId) return

        // 1. PREPARAÇÃO DO CLIENTE: Fetch Unipile Account ID (OBRIGATÓRIO antes de qualquer loop)
        let clientAccountId
        try {
            const { data: client, error } = await supabase
                .from('clients')
                .select('unipile_account_id')
                .eq('id', selectedClientId)
                .single()

            if (error || !client?.unipile_account_id) {
                setNotification({
                    message: "Connect a LinkedIn account in this client's settings.",
                    type: 'error'
                })
                return
            }
            clientAccountId = client.unipile_account_id
        } catch (err) {
            console.error("Error fetching client account ID", err)
            setNotification({ message: "Error fetching client's Unipile account.", type: 'error' })
            return
        }

        // 2. PREPARAÇÃO DOS LEADS: usar o state `leads` (view já é flat, id = ID real do lead)
        let realLeadIds = []
        setNotification({ message: 'Preparing lead list...', type: 'info' })

        if (selectedLeads.size > 0) {
            // Filtrar apenas os leads selecionados do state
            const selectedIds = Array.from(selectedLeads)
            realLeadIds = leads
                .filter(l => selectedIds.includes(l.id))
                .map(l => ({ id: l.id, nome: l.nome }))
        } else {
            // Usar todos os leads carregados no state
            realLeadIds = leads.map(l => ({ id: l.id, nome: l.nome }))
        }

        if (realLeadIds.length === 0) {
            setNotification({ message: 'No leads found to process.', type: 'error' })
            return
        }

        console.log(`[Bulk Sync] Starting import for ${realLeadIds.length} leads with account ${clientAccountId}`)
        console.log(`[Bulk Sync] Lead IDs:`, realLeadIds.map(l => l.id))

        // 3. Initialize Queue
        setImportQueue({
            active: true,
            current: 0,
            total: realLeadIds.length,
            failures: 0,
            currentLeadName: ''
        })

        // 4. O LOOP DE ENVIO: Process Queue (Sequential Loop with Delay)
        let failures = 0

        for (let i = 0; i < realLeadIds.length; i++) {
            const lead = realLeadIds[i]
            const leadName = lead.nome || 'Lead #' + lead.id

            setImportQueue(prev => ({ ...prev, current: i + 1, currentLeadName: leadName }))

            try {
                console.log(`[Bulk Sync] Sending request for lead_id: ${lead.id}`)

                const response = await fetch('https://n8n-n8n-start.kfocge.easypanel.host/webhook/import-history', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        lead_id: lead.id,           // ID REAL do lead (ex: 480)
                        account_id: clientAccountId  // ID da conta Unipile do Cliente
                    })
                })

                if (!response.ok) {
                    throw new Error(`Webhook failed with status ${response.status}`)
                }
            } catch (error) {
                console.error(`Failed to import history for ${leadName} (ID: ${lead.id})`, error)
                failures++
                setImportQueue(prev => ({ ...prev, failures: prev.failures + 1 }))
            }

            // 4. PAUSA DE SEGURANÇA (3 segundos para evitar Rate Limit 429)
            if (i < realLeadIds.length - 1) {
                console.log(`[Bulk Sync] Waiting 3 seconds before next request...`)
                await sleep(3000)
            }
        }

        // 5. Finish
        setImportQueue(prev => ({ ...prev, active: false }))
        setNotification({
            message: `Processing completed! ${realLeadIds.length - failures} successes, ${failures} failures.`,
            type: failures > 0 ? 'info' : 'success'
        })
        setTimeout(() => setNotification(null), 5000)
    }

    // --- HELPER COMPONENTS ---
    const QualificationBadge = ({ isHighTicket, isB2B, companySize }) => {
        return (
            <div className="flex flex-wrap gap-1.5 justify-start">
                {isHighTicket && (
