const PostFeedbackPage = () => {
  const { id } = useParams()
  const navigate = useNavigate()
  const { user, profile, loading: authLoading } = useAuth()
  const [post, setPost] = useState(null)
  const [comments, setComments] = useState([])
  const [loading, setLoading] = useState(true)
  const [messageText, setMessageText] = useState('')
  const [sending, setSending] = useState(false)
  const [uploading, setUploading] = useState(false)

  const commentsEndRef = useRef(null)
  const inputRef = useRef(null)

  const isAdmin = profile?.role === 'admin'
  // Magic Link Logic: If not admin, assume it's the client (Public Access)
  const isClient = !isAdmin

  useEffect(() => { commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' }) }, [comments])

  useEffect(() => {
    if (!id) return
    const fetchData = async () => {
      try {
        // Use single secure RPC for post and comments
        const { data, error } = await supabase.rpc('get_public_post_details', { p_post_id: id })
        
        if (error || data.error) throw new Error(data?.error || error.message)
        
        setPost(data.post)
        setComments(data.comments || [])
      } catch (err) { 
        console.error(err)
        alert('Erro ao carregar dados: ' + err.message)
      } finally { 
        setLoading(false) 
      }
    }
    fetchData()
    const channel = supabase.channel(`post_feed_${id}`).on('postgres_changes', { event: 'INSERT', schema: 'public', table: 'post_comments', filter: `post_id=eq.${id}` }, (pl) => setComments(prev => [...prev, pl.new])).subscribe()
    return () => { supabase.removeChannel(channel) }
  }, [id])

  const handleQuoteParagraph = (text) => {
    const maxLen = 100
    const truncated = text.length > maxLen ? text.substring(0, maxLen) + '...' : text
    const quote = `> "${truncated}"\n\n`

    // Append or set message
    setMessageText(prev => (prev ? prev + '\n' + quote : quote))

    // Scroll and Focus
    commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' })
    setTimeout(() => {
      inputRef.current?.focus()
    }, 300)
  }

  const handleSendMessage = async () => {
    if (!messageText.trim()) return
    setSending(true)
    try {
      const authorName = isAdmin ? 'Link&Lead' : (post?.nome_cliente || 'Cliente')

      // Use secure RPC for comment insertion
      const { data, error } = await supabase.rpc('add_public_comment', {
        p_post_id: id,
        p_content: messageText,
        p_author_name: authorName,
        p_role: isAdmin ? 'admin' : 'client'
      })

      if (error || data.error) throw new Error(data?.error || error.message)

      setMessageText('')
    } catch (err) { alert('Erro ao enviar: ' + err.message) } finally { setSending(false) }
  }

  const handleUpdateStatus = async (newStatus) => {
    if (!isClient) return

    let finalStatus = newStatus
    let successMessage = 'Post Aprovado! 🚀'

    // Smart Approval Logic
    if (newStatus === 'APPROVED') {
      if (post.data_agendamento) {
        finalStatus = 'AGENDADO'
        const date = new Date(post.data_agendamento).toLocaleString('en-US')
        successMessage = `Post aprovado e agendado automaticamente para ${date}! 📅`
      } else {
        successMessage = 'Post aprovado! Aguardando definição de data pela agência. ✅'
      }
    }

    try {
      // Use secure RPC for status update
      const { data, error } = await supabase.rpc('update_public_post', {
        p_post_id: id,
        p_status: finalStatus
      })

      if (error || data.error) throw new Error(data?.error || error.message)

      setPost({ ...post, status: finalStatus })

      if (newStatus === 'APPROVED' || finalStatus === 'AGENDADO') {
        alert(successMessage)
      } else {
        inputRef.current?.focus()
      }
    } catch (err) { alert('Erro ao atualizar status: ' + err.message) }
  }

  const handleImageUpload = async (e) => {
    const file = e.target.files[0]
    if (!file) return
    setUploading(true)
    try {
      const fileName = `${id}_${Date.now()}_${file.name}`
      await supabase.storage.from('post-images').upload(fileName, file)
      const { data: pubData } = supabase.storage.from('post-images').getPublicUrl(fileName)

      // Save as array [url]
      const newImageArray = [pubData.publicUrl]

      // Use secure RPC for image update
      const { data, error } = await supabase.rpc('update_public_post', {
        p_post_id: id,
        p_image_array: newImageArray
      })

      if (error || data.error) throw new Error(data?.error || error.message)

      setPost({ ...post, sugestao_imagem: newImageArray })
    } catch (err) { alert('Erro no upload: ' + err.message) } finally { setUploading(false) }
  }

  if (authLoading || loading) return <div style={{ height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}><Loader2 className="animate-spin" /></div>
  if (!post) return <div>404 Post Not Found</div>

  const normalizedStatus = (post.status || '').toUpperCase()
  let statusObj = { cls: 'status-pending', txt: 'Pendente' }

  if (normalizedStatus === 'APPROVED' || normalizedStatus === 'APROVADO') {
    statusObj = { cls: 'status-approved', txt: 'Aprovado' }
  } else if (normalizedStatus === 'WAITING_APPROVAL' || normalizedStatus === 'PENDING') {
    statusObj = { cls: 'status-pending', txt: 'Aguardando Aprovação' }
  } else if (normalizedStatus === 'CHANGES_REQUESTED' || normalizedStatus.includes('REVI')) {
    statusObj = { cls: 'status-changes', txt: 'Revisão Solicitada' }
  } else if (normalizedStatus === 'AGENDADO') {
    statusObj = { cls: 'status-approved', txt: 'Agendado' } // Reusing approved style for scheduled
  } else if (normalizedStatus === 'POSTADO') {
    statusObj = { cls: 'status-approved', txt: 'Publicado' }
  }

  // Helper to get array
  const images = Array.isArray(post.sugestao_imagem) ? post.sugestao_imagem : post.sugestao_imagem ? [post.sugestao_imagem] : []

  return (
    <div className="feedback-page">
      <style>{pageStyles}</style>

      <div className="page-container">
        <div className="back-nav">
          <button onClick={() => navigate(-1)} className="btn-back">
            <ArrowLeft size={16} /> Voltar
          </button>
        </div>

        {/* --- 1. POST PREVIEW (Top) --- */}
        <div className="post-preview-card">
          {/* Header */}
          <div className="preview-header">
            <div className="preview-avatar">
              {post.nome_cliente ? post.nome_cliente.charAt(0).toUpperCase() : 'C'}
            </div>
            <div className="preview-meta">
              <h3>{post.nome_cliente || 'Nome do Cliente'}</h3>
              <p className="preview-subtext">
                {post.data_agendamento
                  ? `Post Agendado para ${new Date(post.data_agendamento).toLocaleDateString('en-US')}`
                  : 'Post ainda não agendado'
                }
              </p>
            </div>
            <div style={{ marginLeft: 'auto' }}>
              <div className={`status-banner ${statusObj.cls}`}>
                {statusObj.txt}
              </div>
            </div>
          </div>

          {/* Text Content */}
          <div className="post-content-text">
            {post.corpo_post && post.corpo_post.split(/\r?\n/).map((paragraph, idx) => {
              // If it's an empty line, render a small spacer to simulate a paragraph break
              if (!paragraph.trim()) return <div key={idx} style={{ height: '0.5rem' }} />

              return (
                <div key={idx} className="group relative p-1 -mx-1 hover:bg-gray-50 rounded transition-colors flex items-start">
                  <p className="flex-1 whitespace-pre-wrap leading-relaxed">{paragraph}</p>
                  <button
                    onClick={() => handleQuoteParagraph(paragraph)}
                    className="ml-2 opacity-0 group-hover:opacity-100 focus:opacity-100 transition-all text-blue-500 bg-white border border-blue-100 shadow-sm p-1 rounded-md hover:bg-blue-50 hover:text-blue-700 flex-shrink-0"
                    title="Citar este trecho"
                    style={{ marginTop: '0px' }}
                  >
                    <MessageSquarePlus size={14} />
                  </button>
                </div>
              )
            })}
          </div>

          {/* Media Content */}
          <div className="post-media" style={{ position: 'relative', background: '#000', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
            {images.length > 0 ? (
              <div style={{ display: 'flex', overflowX: 'auto', width: '100%', scrollSnapType: 'x mandatory', gap: '4px' }}>
                {images.map((url, idx) => {
                  const isPdf = url.toLowerCase().includes('.pdf')
                  return (
                    <div
                      key={idx}
                      style={{
                        flex: '0 0 100%',
                        width: '100%',
                        height: '600px',
                        scrollSnapAlign: 'start',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        background: '#f1f5f9'
                      }}
                    >
                      {isPdf ? (
                        <div style={{ width: '100%', height: '100%', overflowY: 'hidden', overflowX: 'auto', display: 'flex', scrollSnapType: 'x mandatory' }}>
                          <PdfCarousel url={url} />
                        </div>
                      ) : (
                        <img
                          src={url}
                          alt={`Slide ${idx}`}
                          style={{
                            width: '100%',
                            height: 'auto',
                            maxHeight: '600px',
                            objectFit: 'contain'
                          }}
                        />
                      )}
                    </div>
                  )
                })}
              </div>
            ) : (
              <div className="media-placeholder">
                <ImageIcon size={48} style={{ opacity: 0.3, marginBottom: 4 }} />
                <span>Sem imagem selecionada</span>
              </div>
            )}

            {isClient && (
              <label className="upload-btn-overlay">
                {uploading ? <Loader2 size={12} className="animate-spin" /> : <ImageIcon size={12} />}
                {uploading ? '...' : 'Alterar Imagem'}
                <input type="file" onChange={handleImageUpload} hidden disabled={uploading} />
              </label>
            )}
          </div>

          {/* Mock Footer */}
          <div className="social-footer">
            <div className="mock-action"><ThumbsUp size={16} /> Curtir</div>
            <div className="mock-action"><MessageCircle size={16} /> Comentar</div>
          </div>
        </div>

        {/* --- 2. FEEDBACK (Messages) --- */}
        <div className="feedback-section">
          <div className="feedback-title">Comentários</div>
          <div className="chat-scroll">
            {comments.length === 0 && <div style={{ textAlign: 'center', color: '#cbd5e1', padding: '1rem', fontSize: '0.9rem' }}>Nenhum comentário ainda.</div>}
            {comments.map((msg, i) => {
              const isAdminMsg = msg.role === 'admin'
              return (
                <div key={i} className={`message-row ${isAdminMsg ? 'row-admin' : 'row-client'}`}>
                  <div className={`chat-bubble ${isAdminMsg ? 'bubble-admin' : 'bubble-client'}`}>
                    {msg.content}
                  </div>
                  <div className="chat-meta">{msg.author_name} • {new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</div>
                </div>
              )
            })}
            <div ref={commentsEndRef}></div>
          </div>
        </div>
      </div>

      {/* --- 4. STICKY ACTION BAR (Client Only & Pending) --- */}
      {isClient && (normalizedStatus === 'WAITING_APPROVAL' || normalizedStatus === 'PENDING') && (
        <div className="fixed bottom-0 left-0 right-0 w-full bg-white border-t border-gray-200 z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] mb-[70px]">
          <div className="max-w-[700px] mx-auto px-4 py-4 flex justify-between gap-4">
            <button
              className="flex-1 px-4 py-3 rounded-xl border border-gray-300 text-gray-600 font-bold text-sm hover:bg-gray-50 transition-colors"
              onClick={() => {
                commentsEndRef.current?.scrollIntoView({ behavior: 'smooth' })
                setTimeout(() => {
                  inputRef.current?.focus()
                  setMessageText("Solicito ajuste em: ")
                }, 300)
              }}
            >
              Solicitar Alteração
            </button>

            <button
              className="flex-1 px-4 py-3 rounded-xl bg-green-600 text-white font-bold text-sm hover:bg-green-700 shadow-md transition-transform active:scale-95 flex items-center justify-center gap-2"
              onClick={() => handleUpdateStatus('APPROVED')}
            >
              Aprovar Post <Check size={18} />
            </button>
          </div>
        </div>
      )}

      {/* --- 5. ALWAYS VISIBLE CHAT FOOTER --- */}
      <div className="fixed-footer" style={{ zIndex: 40 }}>
        <div className="footer-content">
          <div className="input-wrapper">
            <input
              ref={inputRef}
              className="chat-input"
              placeholder="Digite sua mensagem..."
              value={messageText}
              onChange={e => setMessageText(e.target.value)}
              onKeyDown={e => e.key === 'Enter' && handleSendMessage()}
            />
            <button className="btn-send" onClick={handleSendMessage} disabled={sending || !messageText.trim()}>
              {sending ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
            </button>
          </div>
        </div>
      </div>

      {/* Helper Spacer to prevent content from being hidden behind footer */}
      <div style={{ height: '100px' }}></div>
    </div>
  )
}

export default PostFeedbackPage

import React, { useState, useEffect } from 'react'
import { supabase } from '../services/supabaseClient'
import { useAuth } from '../contexts/AuthContext'
import { useSearchParams, Link, useNavigate } from 'react-router-dom'
import {
    Loader2,
    ExternalLink,
    FileText,
    Trash2,
    Link as LinkIcon,
    AlertCircle,
    Filter,
    Pencil,
    MessageCircle,
    CalendarClock
} from 'lucide-react'
import EditPostModal from '../components/EditPostModal'
import SchedulePostModal from '../components/SchedulePostModal'
import './PostsPage.css'

const PostsPage = () => {
    // Dashboard States
    // Helper for Status Translation
    const getStatusLabel = (status) => {
        if (!status) return 'Unknown'

        const map = {
            'WAITING_APPROVAL': 'Waiting Approval',
            'CHANGES_REQUESTED': 'Changes Requested',
            'APPROVED': 'Approved',
            'waiting_approval': 'Waiting Approval',
            'changes_requested': 'Changes Requested',
            'approved': 'Approved',
            'postado': 'Posted',
            'POSTADO': 'Posted',
            'AGENDADO': 'Scheduled'
        }

        return map[status] || map[status.toUpperCase()] || map[status.toLowerCase()] || status
    }

    const { profile, loading: authLoading } = useAuth()
    const navigate = useNavigate()
    const [posts, setPosts] = useState([])
    const [loadingPosts, setLoadingPosts] = useState(true)
    const [statusFilter, setStatusFilter] = useState('All')
    const [editingPost, setEditingPost] = useState(null)
    const [schedulingPost, setSchedulingPost] = useState(null)
    const [searchParams] = useSearchParams()
    const clientFilter = searchParams.get('client')

    // Notifications State
    const [unreadCounts, setUnreadCounts] = useState({})

    // Stable Fetch Functions
    // Safe Mount Check
    const isMounted = React.useRef(true)
    useEffect(() => {
        return () => { isMounted.current = false }
    }, [])

    const fetchPosts = React.useCallback(async () => {
        setLoadingPosts(true)
        try {
            let query = supabase
                .from('tabela_projetofred1')
                .select('*')
                .order('id', { ascending: false })
                .range(0, 49) // Limit to last 50 items

            // Role-based filtering
            // IMPORTANT: If Admin, show ALL. If Client, show ONLY THEIRS.
            if (profile?.role === 'client') {
                if (profile.nome_empresa) {
                    query = query.eq('nome_cliente', profile.nome_empresa)
                } else {
                    console.warn('Client without company_name defined.')
                    setPosts([])
                    return
                }
            }
            // Admin gets standard "All Posts" query (unless client param exists for specific filter)
            if (clientFilter && clientFilter.trim() !== '') {
                query = query.eq('nome_cliente', clientFilter)
            }

            const { data, error } = await query
            if (error) throw error

            // BLINDAGEM: Se houver processamento de dados (ex: map), proteja-o
            // Normalize status strictly to Uppercase String or UNKNOWN
            const postsTratados = (data || []).map(post => ({
                ...post,
                status: post.status ? String(post.status).toUpperCase() : 'UNKNOWN'
            }));

            // FORCE STATE UPDATE - NO MOUNT CHECK
            setPosts(postsTratados);

        } catch (err) {
            console.error("CRITICAL error fetching or processing:", err);
        } finally {
            setLoadingPosts(false); // FORÇAR REMOÇÃO DO SPINNER
        }
    }, [profile?.role, profile?.nome_empresa, clientFilter])

    const fetchUnreadMessages = React.useCallback(async () => {
        try {
            const { data, error } = await supabase
                .from('post_comments')
                .select('post_id')
                .eq('read_by_admin', false)
                .eq('role', 'client')

            if (error) throw error

            const counts = {}
            data.forEach(msg => {
                counts[msg.post_id] = (counts[msg.post_id] || 0) + 1
            })
            setUnreadCounts(counts)
        } catch (err) {
            console.error("Error fetching notifications:", err)
        }
    }, [])

    useEffect(() => {
        if (!authLoading && profile) {
            // Initial Load
            fetchPosts()
            fetchUnreadMessages()

            // Realtime subscription (Cleanup enforced)
            const channel = supabase
                .channel('realtime:posts_and_comments')
                .on('postgres_changes', { event: '*', schema: 'public', table: 'tabela_projetofred1' }, () => {
                    fetchPosts()
                })
                .on('postgres_changes', { event: '*', schema: 'public', table: 'post_comments' }, () => {
                    fetchUnreadMessages()
                })
                .subscribe()

            return () => {
                supabase.removeChannel(channel)
            }
        }
    }, [authLoading, profile?.id, fetchPosts, fetchUnreadMessages]) // Primitive dependency + memozied functions



    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this post?')) return

        try {
            const { error } = await supabase
                .from('tabela_projetofred1')
                .delete()
                .eq('id', id)

            if (error) throw error
            setPosts(posts.filter(post => post.id !== id))
        } catch (err) {
            alert('Error deleting: ' + err.message)
        }
    }

    const copyLink = (id) => {
        const url = `${window.location.origin}/aprovacao?id=${id}`
        navigator.clipboard.writeText(url)
        alert('Link copied!')
    }

    const getStatusColor = (status) => {
        const s = (status || 'WAITING_APPROVAL').toUpperCase()
        if (s === 'APPROVED' || s === 'APROVADO' || s.includes('APPROV')) return 'badge-success'
        if (s === 'CHANGES_REQUESTED' || s.includes('CHANGE') || s.includes('REVI')) return 'badge-warning'
        if (s.includes('POSTADO')) return 'badge-purple'
        if (s === 'AGENDADO') return 'badge-purple' // Or another distinctive color like badge-primary
        return 'badge-info'
    }

    // Filter Logic
    const filteredPosts = posts.filter(post => {
        // 1. Client Filter (URL)
        if (clientFilter && clientFilter.trim() !== '' && post.nome_cliente !== clientFilter) return false

        // 2. Tab Filter
        if (statusFilter === 'All') return true

        const s = (post.status || 'WAITING_APPROVAL').toUpperCase()
        if (statusFilter === 'Pending') return s === 'WAITING_APPROVAL' || s.includes('WAITING')
        if (statusFilter === 'Approved') return s === 'APPROVED' || s.includes('APPROV')
        if (statusFilter === 'Revision') return s === 'CHANGES_REQUESTED' || s.includes('REVI')
        return true
    })

    return (
        <div style={{ padding: '0' }}>
            <header className="top-bar">
                <div>
                    <h1>My Posts</h1>
                    {clientFilter && (
                        <span style={{ color: '#64748b', display: 'flex', alignItems: 'center', gap: '0.5rem', marginTop: '0.5rem' }}>
                            <Filter size={16} /> Filtering by client: <strong>{clientFilter}</strong>
                            <Link to="/posts" style={{ color: '#2563eb', fontSize: '0.875rem', marginLeft: '0.5rem' }}>Clear</Link>
                        </span>
                    )}
                </div>
                <div className="user-profile">
                    <span>Agency Admin</span>
                </div>
            </header>

            <div className="filters-bar">
                <div className="tabs">
                    {['All', 'Pending', 'Approved', 'Revision'].map(filter => (
                        <button
                            key={filter}
                            className={`tab-btn ${statusFilter === filter ? 'active' : ''}`}
                            onClick={() => setStatusFilter(filter)}
                        >
                            {filter}
                        </button>
                    ))}
                </div>
            </div>

            <div className="table-container">
                {loadingPosts ? (
                    <div className="loading-state">
                        <Loader2 className="spinner" /> Loading posts...
                    </div>
                ) : (
                    <table className="posts-table">
                        <thead>
                            <tr>
                                <th>ID</th>
                                <th>Client</th>
                                <th>Theme</th>
                                <th>Target Audience</th>
                                <th>Status</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {filteredPosts.length > 0 ? (
                                filteredPosts.map(post => {
                                    const unreadCount = unreadCounts[post.id] || 0
                                    return (
                                        <tr key={post.id}>
                                            <td>#{post.id}</td>
                                            <td className="fw-500">
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                                    {post.nome_cliente || 'N/A'}
                                                    {unreadCount > 0 && (
                                                        <span title={`${unreadCount} new messages`} style={{
                                                            background: '#ef4444',
                                                            color: 'white',
                                                            fontSize: '0.7rem',
                                                            fontWeight: 'bold',
                                                            padding: '0.1rem 0.5rem',
                                                            borderRadius: '99px',
                                                            display: 'flex',
                                                            alignItems: 'center',
                                                            gap: '4px'
                                                        }}>
                                                            <MessageCircle size={10} fill="white" /> {unreadCount}
                                                        </span>
                                                    )}
                                                </div>
                                            </td>
                                            <td>{post.tema || 'No Theme'}</td>
                                            <td>{post.publico || '-'}</td>
                                            <td>
                                                <span className={`badge ${getStatusColor(post.status)}`}>
                                                    {getStatusLabel(post.status)}
                                                </span>
                                            </td>
                                            <td>
                                                <div className="actions-group">
                                                    <button
                                                        className="icon-btn"
                                                        title="Open War Room"
                                                        onClick={() => navigate(`/post-feedback/${post.id}`)}
                                                        style={{ position: 'relative' }}
                                                    >
                                                        <ExternalLink size={18} />
                                                        {unreadCount > 0 && <span style={{ position: 'absolute', top: -2, right: -2, width: 8, height: 8, background: '#ef4444', borderRadius: '50%' }}></span>}
                                                    </button>
                                                    <button
                                                        className="icon-btn"
                                                        title="Edit Post"
                                                        onClick={() => setEditingPost(post)}
                                                    >
                                                        <Pencil size={18} />
                                                    </button>
                                                    <button
                                                        className="icon-btn"
                                                        title="Copy Link"
                                                        onClick={() => copyLink(post.id)}
                                                    >
                                                        <LinkIcon size={18} />
                                                    </button>
                                                    <button
                                                        className="icon-btn text-danger"
                                                        title="Delete"
                                                        onClick={() => handleDelete(post.id)}
                                                    >
                                                        <Trash2 size={18} />
                                                    </button>
                                                    <button
                                                        className="icon-btn"
                                                        title="Schedule Post"
                                                        onClick={() => setSchedulingPost(post)}
                                                        style={{ color: '#8b5cf6' }}
                                                    >
                                                        <CalendarClock size={18} />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    )
                                })
                            ) : (
                                <tr>
                                    <td colSpan="6" style={{ textAlign: 'center', padding: '2rem', color: '#64748b' }}>
                                        No posts found.
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                )}
            </div>

            {editingPost && (
                <EditPostModal
                    post={editingPost}
                    onClose={() => setEditingPost(null)}
                    onSuccess={() => {
                        fetchPosts()
                        setEditingPost(null)
                    }}
                />
            )}

            {schedulingPost && (
                <SchedulePostModal
                    post={schedulingPost}
                    onClose={() => setSchedulingPost(null)}
                    onSuccess={() => {
                        fetchPosts()
                        setSchedulingPost(null)
                    }}
                />
            )}
        </div>
    )
}

export default PostsPage

import React, { useState, useEffect, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '../services/supabaseClient'
import { useClientSelection } from '../contexts/ClientSelectionContext'
import {
    CheckCircle2, Ban, MessageCircle, Loader2, AlertTriangle,
    Users,
    DollarSign,
    Target
} from 'lucide-react'
import LeadAvatar from '../components/LeadAvatar'

// ── helpers ──────────────────────────────────────────────────────────────────
const ICP_BG = { A: '#ecfdf5', B: '#fffbeb', C: '#f3f4f6' }
const ICP_COLOR = { A: '#059669', B: '#d97706', C: '#6b7280' }
const CAD_COLOR = { G1: '#3b82f6', G2: '#3b82f6', G3: '#f59e0b', G4: '#ef4444', G5: '#ef4444' }

const isFollowupDue = (lead) => {
    if (!lead.last_task_completed_at) return false
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000)
    return new Date(lead.last_task_completed_at) < sevenDaysAgo && !lead.has_engaged
}

// ── sub-components ────────────────────────────────────────────────────────────
// eslint-disable-next-line no-unused-vars
const KpiCard = ({ icon: Icon, label, value, color }) => (
    <div style={{ background: '#fff', border: '1px solid #e5e7eb', borderRadius: '10px', padding: '16px 20px', display: 'flex', alignItems: 'center', gap: '14px', boxShadow: '0 1px 3px rgba(0,0,0,0.04)' }}>
        <div style={{ width: 40, height: 40, borderRadius: '8px', background: `${color}18`, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
            <Icon size={18} style={{ color }} />
        </div>
        <div>
            <div style={{ fontSize: '22px', fontWeight: 800, color: '#111827', lineHeight: 1 }}>{value}</div>
            <div style={{ fontSize: '11px', fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', letterSpacing: '0.04em', marginTop: '2px' }}>{label}</div>
        </div>
    </div>
)

const LeadRow = ({ lead, onComplete, onBlacklist, onInbox, completing, blacklisting }) => {
    const followup = isFollowupDue(lead)
    const isLoading = completing || blacklisting

    return (
        <div style={{
            display: 'flex', alignItems: 'center', gap: '14px',
            padding: '14px 20px',
            background: '#fff',
            borderBottom: '1px solid #f3f4f6',
            opacity: isLoading ? 0.5 : 1,
            transition: 'opacity 0.2s, background 0.1s',
        }}
            onMouseEnter={e => { if (!isLoading) e.currentTarget.style.background = '#fafafa' }}
            onMouseLeave={e => { e.currentTarget.style.background = '#fff' }}
        >
            {/* Avatar */}
            <div style={{ width: 40, height: 40, shrink: 0 }}>
                <LeadAvatar
                    lead={lead}
                    className="w-full h-full"
                />
            </div>

            {/* Main info */}
            <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                    <span style={{ fontSize: '14px', fontWeight: 700, color: '#111827' }}>{lead.nome || 'Sem Nome'}</span>
                    {lead.empresa && <span style={{ fontSize: '12px', color: '#9ca3af' }}>· {lead.empresa}</span>}

                    {/* ICP badge */}
                    {lead.icp_score && (
                        <span style={{ fontSize: '10px', fontWeight: 700, padding: '1px 7px', borderRadius: '4px', background: ICP_BG[lead.icp_score] || '#f3f4f6', color: ICP_COLOR[lead.icp_score] || '#6b7280' }}>
                            ICP {lead.icp_score}
                        </span>
                    )}

                    {/* Cadence badge */}
                    {lead.cadence_stage && (
                        <span style={{ fontSize: '10px', fontWeight: 700, padding: '1px 7px', borderRadius: '4px', background: '#eff6ff', color: CAD_COLOR[lead.cadence_stage] || '#3b82f6', border: `1px solid ${CAD_COLOR[lead.cadence_stage] || '#3b82f6'}30` }}>
                            {lead.cadence_stage}
                        </span>
                    )}

                    {/* Follow-up tag */}
                    {followup && (
                        <span style={{ display: 'flex', alignItems: 'center', gap: '4px', fontSize: '10px', fontWeight: 700, padding: '2px 8px', borderRadius: '4px', background: '#fff3ee', color: '#ff4d00', border: '1px solid #ffd4c2' }}>
                            <AlertTriangle size={10} /> Follow-up Necessário
                        </span>
                    )}

                    {/* Stage */}
                    {lead.crm_stage && (
                        <span style={{ fontSize: '10px', fontWeight: 600, padding: '1px 7px', borderRadius: '4px', background: '#f3f4f6', color: '#374151' }}>
                            {lead.crm_stage}
                        </span>
                    )}
                </div>
            </div>

            {/* Actions */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexShrink: 0 }}>
                <button
                    onClick={() => onInbox(lead.id)}
                    title="Ir para o Inbox"
                    style={{ display: 'flex', alignItems: 'center', gap: '5px', padding: '6px 12px', borderRadius: '6px', fontSize: '12px', fontWeight: 600, background: '#fff', border: '1px solid #e5e7eb', color: '#374151', cursor: 'pointer' }}
                    onMouseEnter={e => { e.currentTarget.style.borderColor = '#ff4d00'; e.currentTarget.style.color = '#ff4d00' }}
                    onMouseLeave={e => { e.currentTarget.style.borderColor = '#e5e7eb'; e.currentTarget.style.color = '#374151' }}
                >
                    <MessageCircle size={13} /> Inbox
                </button>

                <button
                    onClick={() => onComplete(lead.id)}
                    disabled={isLoading}
                    title="Marcar como Concluído"
                    style={{ display: 'flex', alignItems: 'center', gap: '5px', padding: '6px 12px', borderRadius: '6px', fontSize: '12px', fontWeight: 600, background: completing ? '#f0fdf4' : '#fff', border: `1px solid ${completing ? '#86efac' : '#e5e7eb'}`, color: '#059669', cursor: isLoading ? 'default' : 'pointer' }}
                    onMouseEnter={e => { if (!isLoading) { e.currentTarget.style.background = '#f0fdf4'; e.currentTarget.style.borderColor = '#86efac' } }}
                    onMouseLeave={e => { if (!isLoading) { e.currentTarget.style.background = '#fff'; e.currentTarget.style.borderColor = '#e5e7eb' } }}
                >
                    {completing ? <Loader2 size={13} style={{ animation: 'spin 1s linear infinite' }} /> : <CheckCircle2 size={13} />}
                    Concluído
                </button>

                <button
                    onClick={() => onBlacklist(lead.id)}
                    disabled={isLoading}
                    title="Mover para Lista Negra"
                    style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: '32px', height: '32px', borderRadius: '6px', background: '#fff', border: '1px solid #e5e7eb', color: '#9ca3af', cursor: isLoading ? 'default' : 'pointer' }}
